css:
/* Win95 Theme — authentic Windows 95 skin for Marinara Engine.
 * All custom selectors are prefixed `win95-`. Engine semantic CSS vars
 * are overridden at :root so we don't fight component-level selectors. */

/* ── Pixel font (W95FA) ──────────────────────────────────────────────
 * The CSS injected by the extension lives in a `<style>` tag, so
 * relative `url(...)` would resolve against the page origin and 404.
 * The font is therefore inlined as a base64 data URI by `build.js`,
 * which substitutes the `data:font/woff2;base64,` token below at bundle
 * time. If `w95fa.woff2` is missing from the repo root the placeholder
 * stays as-is, the URL silently 404s, and the fallback chain
 * (Pixelated MS Sans Serif → MS Sans Serif → Tahoma) takes over.
 * Source: https://www.dafont.com/w95fa.font (open license, ~30 KB). */
@font-face {
  font-family: "W95FA";
  src: url("data:font/woff2;base64,") format("woff2");
  font-weight: normal;
  font-style: normal;
  font-display: swap;
}

/* ── Palette + tokens (overrides engine vars in both light & dark) ── */
:root,
[data-theme="dark"],
[data-theme="light"] {
  --win95-face: #c0c0c0;
  --win95-light: #dfdfdf;
  --win95-hilite: #ffffff;
  --win95-shadow: #808080;
  --win95-dark: #404040;
  --win95-text: #000000;
  --win95-disabled-text: #808080;
  --win95-title-active-1: #000080;
  --win95-title-active-2: #1084d0;
  --win95-title-inactive-1: #808080;
  --win95-title-inactive-2: #b5b5b5;
  --win95-selection-bg: #000080;
  --win95-selection-fg: #ffffff;
  --win95-link: #0000ee;

  /* Engine semantic tokens — re-pointed at the Win95 palette */
  --background: var(--win95-face);
  --foreground: var(--win95-text);
  --card: var(--win95-face);
  --card-foreground: var(--win95-text);
  --popover: var(--win95-face);
  --popover-foreground: var(--win95-text);
  --primary: var(--win95-title-active-1);
  --primary-foreground: var(--win95-hilite);
  --secondary: var(--win95-face);
  --secondary-foreground: var(--win95-text);
  --muted: var(--win95-face);
  --muted-foreground: var(--win95-shadow);
  --accent: #d4d0c8;
  --accent-foreground: var(--win95-text);
  --destructive: #aa0000;
  --destructive-foreground: var(--win95-hilite);
  --border: var(--win95-shadow);
  --input: var(--win95-hilite);
  --ring: var(--win95-title-active-1);

  --sidebar: var(--win95-face);
  --sidebar-foreground: var(--win95-text);
  --sidebar-border: var(--win95-shadow);
  --sidebar-accent: var(--win95-title-active-1);
  --sidebar-accent-foreground: var(--win95-hilite);

  --radius: 0;

  --font-y2k:
    "W95FA", "Pixelated MS Sans Serif", "MS Sans Serif",
    "Microsoft Sans Serif", Tahoma, Geneva, sans-serif;

  --app-font-size: 0.75rem;

  color-scheme: light;
}

/* Selection highlight is a global signature of the theme. */
::selection {
  background: var(--win95-selection-bg);
  color: var(--win95-selection-fg);
}

/* ── Reusable bevels ────────────────────────────────────────────────
 * win95-raised  — buttons & windows in their default (un-pressed) state
 * win95-sunken  — inputs, status bars, content wells
 * win95-pressed — buttons in :active
 * Applied as classes (own elements) and as base styles for engine
 * primitives via attribute selectors below. */
.win95-raised {
  border: 2px solid;
  border-top-color: var(--win95-light);
  border-left-color: var(--win95-light);
  border-right-color: var(--win95-dark);
  border-bottom-color: var(--win95-dark);
  box-shadow:
    inset 1px 1px 0 var(--win95-hilite),
    inset -1px -1px 0 var(--win95-shadow);
  background: var(--win95-face);
  border-radius: 0;
}

.win95-sunken {
  border: 2px solid;
  border-top-color: var(--win95-shadow);
  border-left-color: var(--win95-shadow);
  border-right-color: var(--win95-hilite);
  border-bottom-color: var(--win95-hilite);
  box-shadow:
    inset 1px 1px 0 var(--win95-dark),
    inset -1px -1px 0 var(--win95-light);
  background: var(--win95-hilite);
  border-radius: 0;
}

.win95-pressed {
  border-top-color: var(--win95-dark);
  border-left-color: var(--win95-dark);
  border-right-color: var(--win95-light);
  border-bottom-color: var(--win95-light);
  box-shadow:
    inset 1px 1px 0 var(--win95-shadow),
    inset -1px -1px 0 var(--win95-hilite);
}

/* ── Window chrome (added by JS as siblings of React content) ────── */
.win95-titlebar {
  position: absolute;
  top: 2px;
  left: 2px;
  right: 2px;
  height: 22px;
  padding: 2px 3px 2px 4px;
  display: flex;
  align-items: center;
  gap: 4px;
  background: linear-gradient(
    to right,
    var(--win95-title-active-1) 0%,
    var(--win95-title-active-2) 100%
  );
  color: var(--win95-hilite);
  font-family: var(--font-y2k);
  font-size: 11px;
  font-weight: 700;
  z-index: 5;
  user-select: none;
  pointer-events: none;
}

.win95-titlebar.is-inactive {
  background: linear-gradient(
    to right,
    var(--win95-title-inactive-1) 0%,
    var(--win95-title-inactive-2) 100%
  );
}

.win95-titlebar-title {
  flex: 1;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  letter-spacing: 0.2px;
}

.win95-titlebar-buttons {
  display: flex;
  gap: 2px;
  pointer-events: auto;
}

.win95-titlebar-btn {
  width: 16px;
  height: 14px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-family: "Marlett", "Segoe UI Symbol", sans-serif;
  font-size: 9px;
  font-weight: 700;
  color: var(--win95-text);
  background: var(--win95-face);
  border: 1px solid;
  border-top-color: var(--win95-light);
  border-left-color: var(--win95-light);
  border-right-color: var(--win95-dark);
  border-bottom-color: var(--win95-dark);
  box-shadow:
    inset 1px 1px 0 var(--win95-hilite),
    inset -1px -1px 0 var(--win95-shadow);
  cursor: pointer;
  padding: 0;
  line-height: 1;
}

.win95-titlebar-btn:active {
  border-top-color: var(--win95-dark);
  border-left-color: var(--win95-dark);
  border-right-color: var(--win95-light);
  border-bottom-color: var(--win95-light);
  box-shadow:
    inset 1px 1px 0 var(--win95-shadow),
    inset -1px -1px 0 var(--win95-hilite);
}

.win95-statusbar {
  position: absolute;
  bottom: 2px;
  left: 2px;
  right: 2px;
  height: 20px;
  display: flex;
  gap: 2px;
  padding: 2px;
  background: var(--win95-face);
  z-index: 5;
  font-family: var(--font-y2k);
  font-size: 11px;
  color: var(--win95-text);
  user-select: none;
  pointer-events: none;
}

.win95-statusbar-cell {
  flex: 1 1 auto;
  padding: 1px 6px;
  border: 1px solid;
  border-top-color: var(--win95-shadow);
  border-left-color: var(--win95-shadow);
  border-right-color: var(--win95-hilite);
  border-bottom-color: var(--win95-hilite);
  /* Inset shadow deepens the sunken-well look — real Win95 status
   * panes had this two-pixel inset, not the flat 1px border alone. */
  box-shadow:
    inset 1px 1px 0 var(--win95-dark),
    inset -1px -1px 0 var(--win95-light);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  min-width: 0;
}

.win95-statusbar-cell.is-fixed {
  flex: 0 0 auto;
}

/* When a surface has been wrapped, give it the outer window bevel
 * and reserve space for the decorative titlebar + statusbar.
 * The right panel is skinned via CSS only (its inner header carries
 * the title), so it isn't in this list. */
[data-component="ChatArea.Conversation"].win95-window,
[data-component="ChatArea.Roleplay"].win95-window,
[data-component="ChatSidebar"].win95-window {
  position: relative;
  background: var(--win95-face);
  border: 2px solid;
  border-top-color: var(--win95-light);
  border-left-color: var(--win95-light);
  border-right-color: var(--win95-dark);
  border-bottom-color: var(--win95-dark);
  box-shadow:
    inset 1px 1px 0 var(--win95-hilite),
    inset -1px -1px 0 var(--win95-shadow);
  border-radius: 0;
  padding: 24px 4px 4px;
}

[data-component="ChatArea.Conversation"].win95-window.has-statusbar,
[data-component="ChatArea.Roleplay"].win95-window.has-statusbar {
  padding-bottom: 24px;
}

/* ── Titlebar-button state classes (min / max / closed) ───────
 * Click `_` `□` `×` in any wrapped surface's titlebar — the
 * state machine in win95-theme.js sets one of these classes on
 * the surface and (for `max`) a body-level class. CSS does the
 * actual visual collapse/hide. Restore = click the same button
 * again, or use "Restore all windows" in the win95 settings
 * panel as the safety net. */

/* Minimize: collapse the surface to titlebar height; hide every
 * direct child except the titlebar (statusbar included — there's
 * no room for it at 26px tall). */
.win95-window.win95-state-min {
  flex: 0 0 26px !important;
  min-height: 26px !important;
  max-height: 26px !important;
  height: 26px !important;
  padding: 0 !important;
  overflow: hidden !important;
}
.win95-window.win95-state-min > *:not([data-win95-chrome="titlebar"]) {
  display: none !important;
}
.win95-window.win95-state-min > [data-win95-chrome="titlebar"] {
  position: relative !important;
  top: 0 !important;
  left: 0 !important;
  right: 0 !important;
}

/* Close: same collapse as min, but the titlebar gets the
 * inactive (grey) gradient as a visual cue that the surface is
 * "closed". Click `×` again to restore. */
.win95-window.win95-state-closed {
  flex: 0 0 22px !important;
  min-height: 22px !important;
  max-height: 22px !important;
  height: 22px !important;
  padding: 0 !important;
  overflow: hidden !important;
}
.win95-window.win95-state-closed > *:not([data-win95-chrome="titlebar"]) {
  display: none !important;
}
.win95-window.win95-state-closed > [data-win95-chrome="titlebar"] {
  position: relative !important;
  top: 0 !important;
  left: 0 !important;
  right: 0 !important;
  background: linear-gradient(
    to right,
    var(--win95-title-inactive-1) 0%,
    var(--win95-title-inactive-2) 100%
  ) !important;
}

/* Maximize: hide the sidebar + right-panel siblings via a body
 * class so the chat surface naturally claims the freed space.
 * Selectors target the AppShell wrapper data-components rather
 * than ChatSidebar directly so the user's whole sidebar column
 * disappears (avatar list and all). The ChatArea container
 * itself doesn't need any rule — it'll flex-fill the row. */
body.win95-chat-max [data-component="ChatSidebarPanel"],
body.win95-chat-max [data-component="RightPanelDesktop"],
body.win95-chat-max [data-component="RightPanelMobile"] {
  display: none !important;
}

/* The sidebar's `□` (max) is a no-op — fade the button so users
 * see the action isn't available. The click handler also
 * early-returns for sidebar+max so the state never persists. */
[data-component="ChatSidebar"] > [data-win95-chrome="titlebar"] [data-act="max"] {
  opacity: 0.4;
  cursor: not-allowed;
}

/* The inner `.mari-chat-area` div carries an inline-style linear
 * gradient from the user's "Conversation theme" setting in Settings →
 * Appearance. Inline styles win over class CSS, so we need !important
 * here to flatten it back to the Win95 face color. Roleplay's
 * `.rpg-chat-area` shares the same div, so this defeats both. */
.mari-chat-area {
  background: var(--win95-face) !important;
}

/* Roleplay surface paints two dark overlays on top of `.mari-chat-area`
 * to give it the "immersive RPG" mood — `.rpg-overlay` (linear dark
 * gradient) and `.rpg-vignette` (radial darkening at the edges). With
 * the Win95 face color underneath those read as a dark vignetted
 * gray instead of flat #c0c0c0. Make both invisible — the Win95 chrome
 * is the mood here. */
.rpg-overlay,
.rpg-vignette {
  background: none !important;
  background-image: none !important;
}

/* Crisp message text. The engine optionally applies `WebkitTextStroke`
 * via inline style when the user has the narration text-stroke
 * setting enabled — produces a soft outlined look that on a Win95
 * gray field reads as "blurry". Pin stroke off and kill any text
 * shadow that the engine's `retro-glow-text` or theme overrides may
 * add. Also turn off subpixel font smoothing so MS Sans Serif renders
 * with hard pixel edges, matching the period rasterizer. */
.mari-message-content,
.mari-message-content * {
  -webkit-text-stroke: 0 !important;
  paint-order: normal !important;
  text-shadow: none !important;
}

body,
.mari-chat-area,
.mari-message-content,
.win95-titlebar,
.win95-statusbar,
.mari-message {
  -webkit-font-smoothing: none;
  -moz-osx-font-smoothing: grayscale;
  text-rendering: geometricPrecision;
}

/* Right panel: bevel only, no titlebar — its internal header has its
 * own title + close button, so prepending another would be redundant. */
[data-component="RightPanel"] {
  background: var(--win95-face);
  border: 2px solid;
  border-top-color: var(--win95-light);
  border-left-color: var(--win95-light);
  border-right-color: var(--win95-dark);
  border-bottom-color: var(--win95-dark);
  box-shadow:
    inset 1px 1px 0 var(--win95-hilite),
    inset -1px -1px 0 var(--win95-shadow);
  border-radius: 0;
}

/* Active chat row in the sidebar: hard navy + white text. The engine
 * uses `bg-[var(--sidebar-accent)]` which our :root override resolves
 * to navy, but the row's children re-set their own colors via Tailwind
 * utilities — pin both layers here to guarantee the Win95 selection look. */
[data-component="ChatSidebar"] [role="button"][data-chat-id].bg-\[var\(--sidebar-accent\)\] {
  background: var(--win95-selection-bg) !important; /* Defeats inline/utility opacity blends. */
  color: var(--win95-selection-fg);
  box-shadow: none;
}

[data-component="ChatSidebar"] [role="button"][data-chat-id].bg-\[var\(--sidebar-accent\)\] * {
  color: var(--win95-selection-fg) !important; /* Children re-set their own text colors — flatten. */
}

/* Active CONVO / RP / GM mode tab. The engine marks active tabs with
 * `bg-[var(--sidebar-accent)]`; chat rows already use this class but
 * are scoped via [role="button"][data-chat-id] above, so we can
 * narrow here to plain `<button>` to hit only the mode tabs. Pressed
 * bevel + black text reads as "this tab is selected" without
 * fighting the navy chat-row treatment. */
[data-component="ChatSidebar"] button.bg-\[var\(--sidebar-accent\)\] {
  background: var(--win95-face) !important;
  color: var(--win95-text) !important;
  border-top-color: var(--win95-dark) !important;
  border-left-color: var(--win95-dark) !important;
  border-right-color: var(--win95-light) !important;
  border-bottom-color: var(--win95-light) !important;
  box-shadow:
    inset 1px 1px 0 var(--win95-shadow),
    inset -1px -1px 0 var(--win95-hilite) !important;
  font-weight: 700;
}

/* Message timestamps. The engine renders `.mari-message-timestamp`
 * with `text-[var(--muted-foreground)]/50` (Roleplay) or `/60`
 * (Conversation) — both barely legible on the Win95 face. Pin to
 * solid Win95 text (black) so timestamps read clearly. */
.mari-message-timestamp,
.mari-message-meta .text-\[0\.6875rem\] {
  color: var(--win95-text) !important;
  opacity: 1 !important;
  font-weight: normal !important;
}

/* Character name colors. The engine sets per-character name colors
 * via inline `style={nameColorStyle(c)}` — solid color for hex
 * strings, or a gradient via `WebkitBackgroundClip: text` + a
 * transparent text fill. Both are dressed-up modern aesthetics that
 * look out of place on a Win95 chrome. Flatten to black; defeat both
 * the inline `color` and the gradient text-fill. */
.mari-message-name {
  color: var(--win95-text) !important;
  background: none !important;
  background-image: none !important;
  -webkit-text-fill-color: var(--win95-text) !important;
  background-clip: border-box !important;
  -webkit-background-clip: border-box !important;
}

/* Sidebar chat-list avatar fallback (the letter shown when a chat
 * has no avatar — Homer's "H", TestBot's "T", etc.). The engine
 * paints these as `bg-[var(--secondary)] text-[var(--muted-foreground)]`
 * which under our token overrides should already be gray-on-gray —
 * but in practice the fallback paths can pick up character name
 * colors / accent fills that leak orange / pink through. Pin both
 * background and child text color so the letter always reads as
 * black-on-Win95-face. */
[data-component="ChatSidebar"] div.rounded-full {
  background: var(--win95-face) !important;
}

[data-component="ChatSidebar"] div.rounded-full,
[data-component="ChatSidebar"] div.rounded-full > * {
  color: var(--win95-text) !important;
}

/* Purple / orange / amber Lucide icons inside the chat surfaces.
 * Examples: `RoleplayHUDActionsMenu.tsx`'s purple Sparkles + Trash2
 * pair (the "regen actions" buttons at the top-left of the roleplay
 * surface), the orange "back to top" button hover, and the amber
 * conversation-start divider. Force all to black so the chrome is
 * monochrome — animations stay (pulse, etc.) but the color pulse
 * becomes a contrast pulse instead of a hue cycle. */
[data-component^="ChatArea"] svg[class*="text-purple-"],
[data-component^="ChatArea"] svg[class*="text-pink-"],
[data-component^="ChatArea"] svg[class*="text-orange-"],
[data-component^="ChatArea"] svg[class*="text-amber-"],
[data-component^="ChatArea"] svg[class*="text-violet-"],
[data-component^="ChatArea"] svg[class*="text-rose-"],
[data-component^="ChatArea"] [class*="text-purple-"]:not(svg),
[data-component^="ChatArea"] [class*="text-pink-"]:not(svg),
[data-component^="ChatArea"] [class*="text-orange-"]:not(svg),
[data-component^="ChatArea"] [class*="text-amber-"]:not(svg),
[data-component^="ChatArea"] [class*="text-violet-"]:not(svg),
[data-component^="ChatArea"] [class*="text-rose-"]:not(svg) {
  color: var(--win95-text) !important;
  -webkit-text-fill-color: var(--win95-text) !important;
}

/* Character speaker pill at the top of the Conversation surface
 * (ConversationView.tsx:567 — "Caveman" floating tag with status
 * dot). Engine renders as `bg-black/30 rounded-lg backdrop-blur-sm`.
 * The pill's avatar img has `rounded-full` directly on it, the
 * fallback is a colored letter div. Reframe both: gray Win95 pill
 * with a 1-px shadow border, square avatar, square fallback. */
[data-component^="ChatArea"] [class*="bg-black"][class*="rounded-lg"] {
  background: var(--win95-face) !important;
  border-radius: 0 !important;
  border: 1px solid var(--win95-shadow);
  color: var(--win95-text);
}

[data-component^="ChatArea"] [class*="bg-black"][class*="rounded-lg"] img.rounded-full,
[data-component^="ChatArea"] [class*="bg-black"][class*="rounded-lg"] div.rounded-full {
  border-radius: 0 !important;
  background: var(--win95-face) !important;
  color: var(--win95-text) !important;
}

[data-component^="ChatArea"] [class*="bg-black"][class*="rounded-lg"] .text-foreground\/90,
[data-component^="ChatArea"] [class*="bg-black"][class*="rounded-lg"] .text-foreground\/50 {
  color: var(--win95-text) !important;
}

/* Roleplay user message header timestamp + index. Engine renders
 * these as `text-white/30` / `text-white/25` (designed for the
 * dark-mode roleplay bg). On Win95 gray that's invisible. Pin all
 * `text-white/*` opacity variants in the chat area to solid Win95
 * shadow gray so they read as proper secondary metadata. */
[data-component^="ChatArea"] [class*="text-white/"]:not(.mari-message-bubble):not(.mari-message-bubble *) {
  color: var(--win95-shadow) !important;
}

/* Import buttons in Settings → Import are <label> elements (not
 * <button>) wrapping a hidden file input + a `bg-gradient-to-r ...
 * ring-1 ring-emerald-500/30` (or pink/violet) frame. The earlier
 * gradient kill caught the bg but the colored ring (Tailwind compiles
 * `ring-*` to a box-shadow) survived. Cover labels too and pin the
 * box-shadow to the Win95 raised bevel — kills the colored halos. */
[data-component="RightPanel"] label[class*="bg-gradient-to"] {
  border: 2px solid !important;
  border-top-color: var(--win95-light) !important;
  border-left-color: var(--win95-light) !important;
  border-right-color: var(--win95-dark) !important;
  border-bottom-color: var(--win95-dark) !important;
  box-shadow:
    inset 1px 1px 0 var(--win95-hilite),
    inset -1px -1px 0 var(--win95-shadow) !important;
  --tw-ring-shadow: 0 0 transparent !important;
  --tw-ring-color: transparent !important;
}

/* Defensive: any element that uses the gradient-text trick (inline
 * style with `WebkitTextFillColor: transparent` + `WebkitBackgroundClip:
 * text`) gets its text color flattened to win95-text. The engine
 * applies this on character names in chat list rows when the
 * character has a gradient nameColor configured (see
 * `nameColorStyle` in ConversationMessage.tsx:30). The chat-sidebar
 * sidebar-accent rule above pins descendants to white for the active
 * row; this rule pins all OTHER name colors to black across panels. */
[data-component] [style*="-webkit-text-fill-color"],
[data-component] [style*="WebkitTextFillColor"] {
  -webkit-text-fill-color: var(--win95-text) !important;
  background-image: none !important;
  background: none !important;
  color: var(--win95-text) !important;
}

/* Roleplay-bubble text crispness. The bubbles use `text-neutral-100`
 * (which is `#f5f5f5`, not pure white) over the navy gradient — that
 * faint off-white at small font sizes reads as bold-and-soft. Pin
 * pure white for crisper rendering and ensure font-smoothing is off
 * on the bubble itself (the body-level rule earlier doesn't
 * cascade into `.mari-message-bubble` because Tailwind utilities
 * re-set the family on the bubble's children). */
.mari-message-bubble,
.mari-message-bubble * {
  -webkit-font-smoothing: none;
  -moz-osx-font-smoothing: grayscale;
}

.mari-message-user .mari-message-bubble:not(.texting-bubble) .mari-message-content,
.mari-message-user .mari-message-bubble:not(.texting-bubble) .mari-message-content * {
  color: var(--win95-hilite) !important;
}

/* Square + bevel message avatars. The Discord-style Conversation
 * layout uses round 40×40 avatar slots. Pure round + a placeholder
 * person icon on empty user slots reads as "broken image" against
 * the Win95 chrome. Squaring + a sunken bevel reframes the slot as
 * an authentic 32-bit-era portrait well. */
/* Two avatar render paths:
 *   (a) Message rows (Discord-style ConversationMessage / ChatMessage)
 *       wrap the image in a `<div class="...rounded-full overflow-hidden">`
 *       — square the wrapper, the img inside is plain.
 *   (b) Chat sidebar list avatars put `rounded-full` directly on the
 *       `<img>` element with no wrapper. Square the img.
 * Both get a sunken Win95 portrait-well bevel. */
.mari-message-avatar div.rounded-full,
.mari-message div.rounded-full,
[data-component="ChatSidebar"] img.rounded-full,
[data-component="ChatSidebar"] div.rounded-full {
  border-radius: 0 !important;
}

.mari-message-avatar > div.rounded-full,
.mari-message-avatar > div[class*="rounded-full"] {
  border: 2px solid;
  border-top-color: var(--win95-shadow);
  border-left-color: var(--win95-shadow);
  border-right-color: var(--win95-hilite);
  border-bottom-color: var(--win95-hilite);
  box-shadow:
    inset 1px 1px 0 var(--win95-dark),
    inset -1px -1px 0 var(--win95-light);
  background: var(--win95-face);
}

[data-component="ChatSidebar"] img.rounded-full,
[data-component="ChatSidebar"] div.rounded-full {
  border: 1px solid;
  border-top-color: var(--win95-shadow);
  border-left-color: var(--win95-shadow);
  border-right-color: var(--win95-hilite);
  border-bottom-color: var(--win95-hilite);
}

/* Conversation-mode message text-wells. ConversationMessage.tsx
 * renders body text as plain `.mari-message-content` divs with no
 * enclosing bubble — that's the engine's Discord-style design. To
 * make the flat layout read as a period-correct Win95 message log,
 * frame each body in a sunken white text-well. Roleplay-mode bubbles
 * are styled separately above and aren't affected. */
[data-component="ChatArea.Conversation"] .mari-message-content {
  background: var(--win95-hilite);
  color: var(--win95-text);
  border: 1px solid;
  border-top-color: var(--win95-shadow);
  border-left-color: var(--win95-shadow);
  border-right-color: var(--win95-hilite);
  border-bottom-color: var(--win95-hilite);
  padding: 4px 8px;
  margin-top: 1px;
  display: inline-block;
  max-width: 100%;
}

/* Empty / typing-only renders should not paint a frame around an
 * invisible cell. Hide the well when the content node is empty
 * (typing dots only ever live in a child div, so :empty matches an
 * actual empty render). */
[data-component="ChatArea.Conversation"] .mari-message-content:empty {
  display: none;
}

/* Send / Stop button — replace the modern paper-plane Lucide icon
 * with a Win95-style labeled button. The source code (ChatInput.tsx)
 * sets a `mari-chat-send-btn` class but in the rendered DOM the
 * class doesn't appear — twMerge or a Tailwind v4 layer strips it.
 * The button does carry a stable `title` attribute ("Send" / "Stop")
 * which is what the engine flips between based on streaming state.
 * Target by both selectors so we hit it regardless. */
button[title="Send"],
button[title="Stop"],
button.mari-chat-send-btn,
.mari-chat-input-box button[title="Send"],
.mari-chat-input-box button[title="Stop"] {
  width: auto !important;
  height: auto !important;
  min-width: 64px !important;
  min-height: 22px !important;
  padding: 3px 14px !important;
}

button[title="Send"] > svg,
button[title="Stop"] > svg,
button.mari-chat-send-btn > svg {
  display: none !important;
}

button[title="Send"]::after {
  content: "Send";
  font-family: var(--font-y2k);
  font-size: 11px;
  font-weight: 700;
  color: var(--win95-text);
  letter-spacing: 0.2px;
  display: inline-block;
}

button[title="Stop"]::after {
  content: "Stop";
  font-family: var(--font-y2k);
  font-size: 11px;
  font-weight: 700;
  color: var(--win95-text);
  letter-spacing: 0.2px;
  display: inline-block;
}

button.mari-chat-send-btn::after {
  content: "Send";
  font-family: var(--font-y2k);
  font-size: 11px;
  font-weight: 700;
  color: var(--win95-text);
  letter-spacing: 0.2px;
  display: inline-block;
}

button.mari-chat-send-btn:has(svg[class*="stop"])::after,
button.mari-chat-send-btn:has(svg[class*="circle-stop"])::after {
  content: "Stop";
}

/* Outer chat input wrapper. Engine renders as
 *   <div className="mari-chat-input chat-input-container px-3 pb-3">
 * with no background — the chat-surface gray shows through, leaving
 * the inner `.mari-chat-input-box` looking like a floating pill.
 * Frame it as a proper Win95 toolbar tray with a 1-px shadow border
 * separating it from the message scroll above, and pin all rounded
 * descendants to square. */
.mari-chat-input,
.chat-input-container {
  background: var(--win95-face) !important;
  border-radius: 0 !important;
  padding: 4px !important;
  border-top: 1px solid var(--win95-shadow) !important;
}

.mari-chat-input *,
.chat-input-container * {
  border-radius: 0 !important;
}

/* Chat input wrapper. Engine renders `.mari-chat-input-box` with
 * `bg-black/40 rounded-2xl border-2` — period-incorrect. Reframe as a
 * Win95 dialog toolbar with a raised bevel; the textarea inside gets
 * its own sunken text-control look so the input itself reads as a
 * single-line edit field. Inner toolbar buttons (paperclip, emoji,
 * link, help) keep the generic Win95 button bevel and tighten up. */
.mari-chat-input-box {
  background: var(--win95-face) !important;
  border: 2px solid !important;
  border-top-color: var(--win95-light) !important;
  border-left-color: var(--win95-light) !important;
  border-right-color: var(--win95-dark) !important;
  border-bottom-color: var(--win95-dark) !important;
  box-shadow:
    inset 1px 1px 0 var(--win95-hilite),
    inset -1px -1px 0 var(--win95-shadow) !important;
  border-radius: 0 !important;
  padding: 4px 6px !important;
  gap: 4px !important;
}

.mari-chat-input-textarea {
  background: var(--win95-hilite) !important;
  color: var(--win95-text) !important;
  border: 2px solid !important;
  border-top-color: var(--win95-shadow) !important;
  border-left-color: var(--win95-shadow) !important;
  border-right-color: var(--win95-hilite) !important;
  border-bottom-color: var(--win95-hilite) !important;
  box-shadow:
    inset 1px 1px 0 var(--win95-dark),
    inset -1px -1px 0 var(--win95-light) !important;
  border-radius: 0 !important;
  padding: 3px 6px !important;
  font-family: var(--font-y2k) !important;
  font-size: 11px !important;
}

.mari-chat-input-box button:not(.mari-chat-send-btn) {
  width: auto !important;
  height: auto !important;
  min-height: 22px !important;
  min-width: 0 !important;
  padding: 2px 6px !important;
}

/* Persona status footer at the bottom of the chat sidebar
 * (UserStatusFooter — green dot + "Active" / "Idle" / "DND" label).
 * Reframe the row as a Win95 sunken status-bar cell so it visually
 * matches the chat-area status bar at the bottom of the conversation
 * surface. The colored status dot stays — it's tiny and reads as a
 * period-correct LED indicator next to the label. */
[data-component="ChatSidebar"] > div.relative.border-t {
  background: var(--win95-face) !important;
  padding: 2px !important;
  border: 0 !important;
  border-top: 1px solid var(--win95-shadow) !important;
}

[data-component="ChatSidebar"] > div.relative.border-t > button {
  background: var(--win95-face) !important;
  color: var(--win95-text) !important;
  border: 1px solid !important;
  border-top-color: var(--win95-shadow) !important;
  border-left-color: var(--win95-shadow) !important;
  border-right-color: var(--win95-hilite) !important;
  border-bottom-color: var(--win95-hilite) !important;
  box-shadow: none !important;
  border-radius: 0 !important;
  padding: 2px 6px !important;
  min-height: 0 !important;
  font-family: var(--font-y2k);
  font-size: 11px;
  text-align: left;
}

/* "+ New chat" button in the sidebar header. Engine renders it as
 * a small icon-only button — relabel as a wider Win95 "New" button
 * to match the Send/Stop language. Title prefix is stable: it's
 * always "New <Mode>" (e.g. "New Conversation"). */
.mari-sidebar-header button[title^="New "] {
  min-width: 48px;
  width: auto !important;
  padding: 2px 10px !important;
  min-height: 22px !important;
}

.mari-sidebar-header button[title^="New "] > svg {
  display: none !important;
}

.mari-sidebar-header button[title^="New "]::after {
  content: "New";
  font-family: var(--font-y2k);
  font-size: 11px;
  font-weight: 700;
  color: var(--win95-text);
}

/* Monochrome the right-panel resource-type accent colors. The engine
 * paints placeholder avatar squares + action buttons + badges in the
 * Tailwind palette (pink/orange/purple/emerald/sky) keyed to each
 * resource type. Period-incorrect — flatten all `bg-gradient-*`
 * elements in panels to Win95 face + sunken bevel for placeholders
 * and Win95 button bevel for action buttons. `bg-[var(--primary)]/N`
 * is NOT in this list — it's how active selection / chat-rows are
 * rendered, and we already style those separately. */
[data-component="RightPanel"] [class*="bg-gradient-to"] {
  background: var(--win95-face) !important;
  background-image: none !important;
  color: var(--win95-text) !important;
  border-radius: 0 !important;
  text-shadow: none !important;
}

/* Action buttons (e.g. "Open Full Library", "+ New Character") use
 * `bg-gradient-to-r` + white text + colored shadow. Defeat the shadow
 * and re-apply the standard Win95 raised button bevel, since the
 * generic button rule above is element-level (specificity 0,0,1) and
 * loses to the `[class*="bg-gradient"]` rule (0,1,0). */
[data-component="RightPanel"] button[class*="bg-gradient-to"],
[data-component="RightPanel"] [role="button"][class*="bg-gradient-to"] {
  border: 2px solid !important;
  border-top-color: var(--win95-light) !important;
  border-left-color: var(--win95-light) !important;
  border-right-color: var(--win95-dark) !important;
  border-bottom-color: var(--win95-dark) !important;
  box-shadow:
    inset 1px 1px 0 var(--win95-hilite),
    inset -1px -1px 0 var(--win95-shadow) !important;
}

/* Placeholder avatar squares: sunken portrait well, not raised. */
[data-component="RightPanel"] div[class*="bg-gradient-to-br"]:not(button):not([role="button"]) {
  border: 2px solid !important;
  border-top-color: var(--win95-shadow) !important;
  border-left-color: var(--win95-shadow) !important;
  border-right-color: var(--win95-hilite) !important;
  border-bottom-color: var(--win95-hilite) !important;
  box-shadow:
    inset 1px 1px 0 var(--win95-dark),
    inset -1px -1px 0 var(--win95-light) !important;
}

/* Colored chip / badge elements ("DEFAULT", tag chips). The engine
 * uses `bg-purple-400/15 text-purple-400`-style faint-color pills.
 * Reframe as Win95 monochrome chips — gray field + dark shadow text
 * + 1-pixel sunken border. */
[data-component="RightPanel"] span[class*="bg-purple-400"],
[data-component="RightPanel"] span[class*="bg-pink-400"],
[data-component="RightPanel"] span[class*="bg-amber-400"],
[data-component="RightPanel"] span[class*="bg-orange-400"],
[data-component="RightPanel"] span[class*="bg-rose-400"],
[data-component="RightPanel"] span[class*="bg-violet-400"],
[data-component="RightPanel"] span[class*="bg-fuchsia-400"],
[data-component="RightPanel"] span[class*="bg-sky-400"] {
  background: var(--win95-shadow) !important;
  color: var(--win95-hilite) !important;
  border-radius: 0 !important;
  padding: 1px 4px !important;
  font-family: var(--font-y2k);
  font-size: 10px;
  text-shadow: none !important;
}

/* Tag chips on character cards use `bg-[var(--primary)]/8` — these
 * are scoped to span.rounded-full inside the card grid so we don't
 * collide with the active-row chat selection (which uses a div, not
 * span, and isn't rounded-full). */
[data-component="RightPanel"] span.rounded-full[class*="bg-[var(--primary)]"] {
  background: var(--win95-face) !important;
  color: var(--win95-text) !important;
  border: 1px solid var(--win95-shadow);
  border-radius: 0 !important;
  padding: 1px 4px !important;
  font-family: var(--font-y2k);
  font-size: 10px;
  text-shadow: none !important;
}

/* Rainbow `.retro-divider` (animated conic gradient horizontal line)
 * is straight Y2K — defeat with a Win95 sunken horizontal rule. */
.retro-divider {
  height: 2px !important;
  margin: 8px 0 !important;
  background: none !important;
  border-top: 1px solid var(--win95-shadow) !important;
  border-bottom: 1px solid var(--win95-hilite) !important;
  border-radius: 0 !important;
  animation: none !important;
}

/* Kill backdrop blur globally — Win95 didn't have frosted glass.
 * The engine sprinkles `backdrop-blur-*` on top bars, modals, panel
 * headers, and the avatar speaker pill (the "Caveman" widget that
 * renders mid-chat). All of them collapse cleanly to flat opaque
 * backgrounds via our Win95 palette overrides. */
* {
  backdrop-filter: none !important;
  -webkit-backdrop-filter: none !important;
}

/* The chat input wrapper still inherits some rounded corners through
 * Tailwind utility classes on inner elements (textarea ring, button
 * ring backgrounds). Nuke border-radius on everything inside, since
 * Win95 has zero rounded geometry anywhere. */
.mari-chat-input-box,
.mari-chat-input-box * {
  border-radius: 0 !important;
}

/* Win95 cursor. The engine paints a Y2K pink arrow via `--cursor-pink`
 * across body / chat / sidebar / etc. Repoint at a black-outlined
 * white pointer (the same SVG shape the engine uses, recolored), and
 * the cursor switches everywhere those rules apply without touching
 * any of the engine's `cursor: var(--cursor-pink), auto` declarations. */
:root,
[data-theme="dark"],
[data-theme="light"] {
  --cursor-pink: url("data:image/svg+xml,%3Csvg width='24' height='24' viewBox='0 0 24 24' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M3 3L10 20L12 12L20 10L3 3Z' fill='%23FFFFFF' stroke='%23000000' stroke-width='1.5' stroke-linejoin='round'/%3E%3C/svg%3E");
}

/* Force the Win95 pointer on the surfaces the engine doesn't already
 * paint with --cursor-pink — overlay/modal/dropdown surfaces, the
 * right panel, and any deep descendants that opt into `cursor: auto`
 * by default. Skip text inputs (they should keep the I-beam) and
 * disabled/loading states. */
body,
[data-component],
[data-component] *:not(input):not(textarea):not([disabled]):not([aria-disabled="true"]) {
  cursor: var(--cursor-pink), default;
}

/* Right-panel tab bar (General / Appearance / Themes / Extensions /
 * Import / Advanced). The engine renders these as flat text buttons
 * with a small accent underline on the active one. Reframe them as
 * Win95 dialog tabs: raised inactive, pressed-in active. We detect
 * active via :has() over the underline span (only mounted on the
 * active tab — see SettingsPanel.tsx). The native underline span is
 * hidden since the bevel state already conveys selection. */
/* Force the tab row to a single non-wrapping line. Aggressive
 * compression (10px font + 1px-3px padding) is enough to fit all
 * six tabs (General/Appearance/Themes/Extensions/Import/Advanced)
 * inside the typical right-panel width (≈ 320–380 px). The
 * scrollbar is hidden as a fallback so any narrow viewport that
 * still overflows scrolls invisibly rather than showing the ugly
 * native scrollbar inline with the chrome. */
[data-component="RightPanel"] .border-b {
  flex-wrap: nowrap !important;
  overflow-x: auto;
  scrollbar-width: none;
}
[data-component="RightPanel"] .border-b::-webkit-scrollbar {
  display: none !important;
  width: 0 !important;
  height: 0 !important;
}

[data-component="RightPanel"] .border-b > button {
  background: var(--win95-face) !important;
  color: var(--win95-text) !important;
  border: 2px solid !important;
  border-top-color: var(--win95-light) !important;
  border-left-color: var(--win95-light) !important;
  border-right-color: var(--win95-dark) !important;
  border-bottom-color: var(--win95-dark) !important;
  box-shadow:
    inset 1px 1px 0 var(--win95-hilite),
    inset -1px -1px 0 var(--win95-shadow) !important;
  border-radius: 0 !important;
  padding: 1px 3px !important;
  min-height: 0 !important;
  margin: 0 1px 0 0 !important;
  font-size: 0.625rem !important;
  white-space: nowrap !important;
  letter-spacing: 0 !important;
  flex-shrink: 0 !important;
}

[data-component="RightPanel"] .border-b > button:has(> span[class*="bg-[var(--primary)]"]) {
  border-top-color: var(--win95-dark) !important;
  border-left-color: var(--win95-dark) !important;
  border-right-color: var(--win95-light) !important;
  border-bottom-color: var(--win95-light) !important;
  box-shadow:
    inset 1px 1px 0 var(--win95-shadow),
    inset -1px -1px 0 var(--win95-hilite) !important;
  font-weight: 700;
}

[data-component="RightPanel"] .border-b > button > span.absolute.bottom-0 {
  display: none;
}

/* Conversation-mode message bubbles. The engine writes inline
 * `backgroundColor: rgba(23,23,23, …)` styles on each bubble (dark-mode
 * tuned) which collapse against our gray field; defeat with !important
 * and re-paint in the Win95 palette. User bubbles get the title-bar
 * gradient (selection blue), assistant bubbles get the white sunken
 * text-well look. */
.mari-message-bubble.texting-bubble-user {
  background: var(--win95-title-active-1) !important;
  background-image: none !important;
  color: var(--win95-hilite) !important;
  box-shadow: none !important;
  border-radius: 0 !important;
}

.mari-message-bubble.texting-bubble-other {
  background: var(--win95-hilite) !important;
  color: var(--win95-text) !important;
  border: 2px solid;
  border-top-color: var(--win95-shadow);
  border-left-color: var(--win95-shadow);
  border-right-color: var(--win95-hilite);
  border-bottom-color: var(--win95-hilite);
  box-shadow:
    inset 1px 1px 0 var(--win95-dark),
    inset -1px -1px 0 var(--win95-light) !important;
  border-radius: 0 !important;
}

/* Roleplay-mode message bubbles. ChatMessage.tsx renders these as
 * `.mari-message-bubble` *without* a `.texting-bubble` class (that's
 * the conversation/iMessage path), with an inline
 * `style={{ backgroundColor: rgba(23,23,23,…) }}` and Tailwind
 * `text-white/90` / `text-neutral-100`. Defeat both. The wrapper
 * carries `.mari-message-user` / `.mari-message-assistant` from
 * ChatMessage.tsx:1068, which we use to differentiate user vs
 * assistant for the navy/white treatment. */
.mari-message-bubble:not(.texting-bubble) {
  background: var(--win95-hilite) !important;
  color: var(--win95-text) !important;
  border: 2px solid !important;
  border-top-color: var(--win95-shadow) !important;
  border-left-color: var(--win95-shadow) !important;
  border-right-color: var(--win95-hilite) !important;
  border-bottom-color: var(--win95-hilite) !important;
  box-shadow:
    inset 1px 1px 0 var(--win95-dark),
    inset -1px -1px 0 var(--win95-light) !important;
  border-radius: 0 !important;
}

.mari-message-user .mari-message-bubble:not(.texting-bubble) {
  background: var(--win95-title-active-1) !important;
  background-image: none !important;
  color: var(--win95-hilite) !important;
  border-top-color: var(--win95-title-active-1) !important;
  border-left-color: var(--win95-title-active-1) !important;
  border-right-color: var(--win95-title-active-1) !important;
  border-bottom-color: var(--win95-title-active-1) !important;
  box-shadow: none !important;
}

/* Roleplay user messages keep the engine's `.mari-message-content`
 * but Tailwind `text-white/90` colors stick on descendants — force
 * white for user bubbles. Scoped to the Roleplay surface only;
 * Conversation user messages now sit in white text-wells (added
 * above) and need black text inherited from the generic
 * `.mari-message-content` rule. */
[data-component="ChatArea.Roleplay"] .mari-message-user .mari-message-content,
[data-component="ChatArea.Roleplay"] .mari-message-user .mari-message-content * {
  color: var(--win95-hilite) !important;
}

/* The engine hardcodes `.mari-message-content { color: #c3c2c2 }` in
 * globals.css for the dark theme. On our `#c0c0c0` field that's
 * effectively invisible (3 RGB units apart). Conversation mode uses
 * a flat Discord-style layout (no bubble) so we target
 * `.mari-message-content` directly with a descendant `*` to flatten
 * nested Tailwind utility colors (markdown spans, link tokens, etc.).
 * The user-bubble override below wins back navy/white for the
 * Roleplay-mode iMessage path. */
.mari-message-content,
.mari-message-content * {
  color: var(--win95-text) !important;
}

.mari-message-bubble.texting-bubble-user .mari-message-content,
.mari-message-bubble.texting-bubble-user .mari-message-content * {
  color: var(--win95-hilite) !important;
}

/* ── Form controls ─────────────────────────────────────────────── */
button:not(.win95-titlebar-btn):not(.win95-skip):not([data-component="Modal"] [aria-label]),
.button,
[role="button"]:not(.win95-skip) {
  font-family: var(--font-y2k);
  font-size: 11px;
  color: var(--win95-text);
  background: var(--win95-face);
  border: 2px solid;
  border-top-color: var(--win95-light);
  border-left-color: var(--win95-light);
  border-right-color: var(--win95-dark);
  border-bottom-color: var(--win95-dark);
  box-shadow:
    inset 1px 1px 0 var(--win95-hilite),
    inset -1px -1px 0 var(--win95-shadow);
  border-radius: 0 !important; /* Defeats Tailwind rounded-* utilities baked into engine markup. */
  padding: 3px 10px;
  min-height: 22px;
  cursor: default;
}

button:not(.win95-titlebar-btn):not(.win95-skip):active,
.button:active,
[role="button"]:not(.win95-skip):active {
  border-top-color: var(--win95-dark);
  border-left-color: var(--win95-dark);
  border-right-color: var(--win95-light);
  border-bottom-color: var(--win95-light);
  box-shadow:
    inset 1px 1px 0 var(--win95-shadow),
    inset -1px -1px 0 var(--win95-hilite);
}

button:focus-visible:not(.win95-titlebar-btn),
[role="button"]:focus-visible {
  outline: 1px dotted var(--win95-text);
  outline-offset: -4px;
}

button:disabled,
[role="button"][aria-disabled="true"] {
  color: var(--win95-disabled-text);
  text-shadow: 1px 1px 0 var(--win95-hilite);
}

input[type="text"],
input[type="search"],
input[type="email"],
input[type="number"],
input[type="password"],
input[type="url"],
input[type="tel"],
input:not([type]),
textarea,
select {
  font-family: var(--font-y2k);
  font-size: 11px;
  color: var(--win95-text);
  background: var(--win95-hilite);
  border: 2px solid;
  border-top-color: var(--win95-shadow);
  border-left-color: var(--win95-shadow);
  border-right-color: var(--win95-hilite);
  border-bottom-color: var(--win95-hilite);
  box-shadow:
    inset 1px 1px 0 var(--win95-dark),
    inset -1px -1px 0 var(--win95-light);
  border-radius: 0 !important; /* Same Tailwind defeat as buttons. */
  padding: 3px 4px;
}

input:focus,
textarea:focus,
select:focus {
  outline: none;
}

input[type="checkbox"],
input[type="radio"] {
  appearance: none;
  -webkit-appearance: none;
  width: 13px;
  height: 13px;
  background: var(--win95-hilite);
  border: 2px solid;
  border-top-color: var(--win95-shadow);
  border-left-color: var(--win95-shadow);
  border-right-color: var(--win95-hilite);
  border-bottom-color: var(--win95-hilite);
  box-shadow:
    inset 1px 1px 0 var(--win95-dark),
    inset -1px -1px 0 var(--win95-light);
  border-radius: 0;
  display: inline-block;
  position: relative;
  vertical-align: middle;
  cursor: default;
}

input[type="radio"] {
  border-radius: 50%;
  box-shadow: none;
}

input[type="checkbox"]:checked::after {
  content: "";
  position: absolute;
  top: 0;
  left: 2px;
  width: 5px;
  height: 8px;
  border: solid var(--win95-text);
  border-width: 0 2px 2px 0;
  transform: rotate(45deg);
}

input[type="radio"]:checked::after {
  content: "";
  position: absolute;
  inset: 2px;
  border-radius: 50%;
  background: var(--win95-text);
}

/* ── Scrollbars (webkit-only — Firefox keeps native) ─────────────── */
* {
  scrollbar-width: auto;
  scrollbar-color: var(--win95-face) var(--win95-shadow);
}

::-webkit-scrollbar {
  width: 16px;
  height: 16px;
}

::-webkit-scrollbar-track {
  background-color: var(--win95-face);
  background-image:
    linear-gradient(45deg, var(--win95-light) 25%, transparent 25%, transparent 75%, var(--win95-light) 75%),
    linear-gradient(45deg, var(--win95-light) 25%, transparent 25%, transparent 75%, var(--win95-light) 75%);
  background-size: 2px 2px;
  background-position: 0 0, 1px 1px;
  background-color: #c8c8c8;
}

::-webkit-scrollbar-thumb {
  background: var(--win95-face);
  border: 2px solid;
  border-top-color: var(--win95-light);
  border-left-color: var(--win95-light);
  border-right-color: var(--win95-dark);
  border-bottom-color: var(--win95-dark);
  box-shadow:
    inset 1px 1px 0 var(--win95-hilite),
    inset -1px -1px 0 var(--win95-shadow);
}

::-webkit-scrollbar-corner {
  background: var(--win95-face);
}

::-webkit-scrollbar-button {
  background: var(--win95-face);
  border: 2px solid;
  border-top-color: var(--win95-light);
  border-left-color: var(--win95-light);
  border-right-color: var(--win95-dark);
  border-bottom-color: var(--win95-dark);
  box-shadow:
    inset 1px 1px 0 var(--win95-hilite),
    inset -1px -1px 0 var(--win95-shadow);
  display: block;
  width: 16px;
  height: 16px;
  background-repeat: no-repeat;
  background-position: center;
}

::-webkit-scrollbar-button:active {
  border-top-color: var(--win95-dark);
  border-left-color: var(--win95-dark);
  border-right-color: var(--win95-light);
  border-bottom-color: var(--win95-light);
  box-shadow:
    inset 1px 1px 0 var(--win95-shadow),
    inset -1px -1px 0 var(--win95-hilite);
}

::-webkit-scrollbar-button:vertical:start {
  background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' width='7' height='4' viewBox='0 0 7 4'><polygon points='3.5,0 7,4 0,4' fill='%23000'/></svg>");
}
::-webkit-scrollbar-button:vertical:end {
  background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' width='7' height='4' viewBox='0 0 7 4'><polygon points='0,0 7,0 3.5,4' fill='%23000'/></svg>");
}
::-webkit-scrollbar-button:horizontal:start {
  background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' width='4' height='7' viewBox='0 0 4 7'><polygon points='0,3.5 4,0 4,7' fill='%23000'/></svg>");
}
::-webkit-scrollbar-button:horizontal:end {
  background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' width='4' height='7' viewBox='0 0 4 7'><polygon points='0,0 4,3.5 0,7' fill='%23000'/></svg>");
}

/* The double-arrow buttons at each track end are not standard webkit;
 * single arrows on each end is the canonical Win95 layout we ship. */
::-webkit-scrollbar-button:vertical:start:decrement,
::-webkit-scrollbar-button:vertical:end:increment,
::-webkit-scrollbar-button:horizontal:start:decrement,
::-webkit-scrollbar-button:horizontal:end:increment {
  display: block;
}

::-webkit-scrollbar-button:vertical:start:increment,
::-webkit-scrollbar-button:vertical:end:decrement,
::-webkit-scrollbar-button:horizontal:start:increment,
::-webkit-scrollbar-button:horizontal:end:decrement {
  display: none;
}

/* ── Modals ─────────────────────────────────────────────────────
 * Engine structure (Modal.tsx):
 *   [data-component="Modal"]         — full-viewport `fixed inset-0`
 *                                       overlay (do NOT style here —
 *                                       its `::before` would cover
 *                                       the whole screen with a fake
 *                                       titlebar).
 *   .mari-modal-backdrop             — black/60 backdrop dimmer.
 *   .mari-modal-panel.os-window      — the actual dialog frame
 *                                       (this is what we Win95-ize).
 * `.os-window` is also defined in globals.css with a Y2K dark/purple
 * look — overriding it here Win95-izes every os-window in the app
 * (consistent with this being the Win95 theme). */
[data-component="Modal"] {
  background: transparent !important;
  border: 0 !important;
  box-shadow: none !important;
  padding: 0 !important;
  font-family: var(--font-y2k);
}

.mari-modal-backdrop {
  background: rgba(0, 0, 0, 0.5) !important;
  backdrop-filter: none !important;
}

.mari-modal-panel,
.os-window {
  background: var(--win95-face) !important;
  color: var(--win95-text) !important;
  border: 2px solid !important;
  border-top-color: var(--win95-light) !important;
  border-left-color: var(--win95-light) !important;
  border-right-color: var(--win95-dark) !important;
  border-bottom-color: var(--win95-dark) !important;
  box-shadow:
    inset 1px 1px 0 var(--win95-hilite),
    inset -1px -1px 0 var(--win95-shadow),
    2px 2px 0 var(--win95-dark) !important;
  border-radius: 0 !important;
  padding-top: 28px !important;
  position: relative !important;
  backdrop-filter: none !important;
}

.mari-modal-panel::before,
.os-window::before {
  content: "" !important;
  position: absolute !important;
  top: 2px !important;
  left: 2px !important;
  right: 2px !important;
  height: 22px !important;
  background: linear-gradient(
    to right,
    var(--win95-title-active-1) 0%,
    var(--win95-title-active-2) 100%
  ) !important;
  pointer-events: none !important;
  z-index: 1 !important;
  border-radius: 0 !important;
}

/* Modal panel content — paint it black on Win95 face. The engine's
 * dialogs use `text-foreground/X` color tokens which under our
 * overrides resolve correctly, but inputs and form controls inside
 * dialogs sometimes carry their own dark-themed Tailwind utilities
 * that need flattening. */
.mari-modal-panel,
.mari-modal-panel *,
.os-window,
.os-window * {
  color: var(--win95-text) !important;
  text-shadow: none !important;
}

/* Modal native header → Win95 titlebar. The engine's Modal renders
 * its own header (`<h2>{title}</h2>` + close `<X>` button) below
 * our decorative ::before strip — that produced a stacked
 * empty-blue-strip + grey-header look that wasn't authentic. Hide
 * the decorative strip on real modals only (.mari-modal-panel),
 * drop the padding-top hack, and restyle the native header div as
 * the actual Win95 title bar with white-on-blue title and an
 * inset close button. .os-window (used elsewhere) keeps its
 * decorative strip since those surfaces don't have native headers. */
.mari-modal-panel {
  padding-top: 0 !important;
}

.mari-modal-panel::before {
  display: none !important;
}

.mari-modal-panel > .shrink-0.flex.items-center.justify-between {
  background: linear-gradient(
    to right,
    var(--win95-title-active-1) 0%,
    var(--win95-title-active-2) 100%
  ) !important;
  border: 0 !important;
  border-bottom: 1px solid var(--win95-shadow) !important;
  padding: 2px 2px 2px 6px !important;
  min-height: 22px !important;
  font-family: var(--font-y2k) !important;
}

.mari-modal-panel > .shrink-0.flex.items-center.justify-between > h2 {
  color: var(--win95-hilite) !important;
  font-size: 0.6875rem !important;
  font-weight: bold !important;
  margin: 0 !important;
  padding: 0 !important;
  line-height: 18px !important;
  font-family: var(--font-y2k) !important;
  letter-spacing: 0 !important;
}

/* Close button inside the native header — restyle as Win95 close
 * button (small raised square with bold ×). The button keeps its
 * onClick (Modal's onClose), so functionality is preserved. */
.mari-modal-panel > .shrink-0.flex.items-center.justify-between > button {
  background: var(--win95-face) !important;
  border: 1px solid !important;
  border-top-color: var(--win95-light) !important;
  border-left-color: var(--win95-light) !important;
  border-right-color: var(--win95-dark) !important;
  border-bottom-color: var(--win95-dark) !important;
  box-shadow:
    inset 1px 1px 0 var(--win95-hilite),
    inset -1px -1px 0 var(--win95-shadow) !important;
  border-radius: 0 !important;
  padding: 0 !important;
  width: 18px !important;
  height: 16px !important;
  min-width: 18px !important;
  color: var(--win95-text) !important;
  display: inline-flex !important;
  align-items: center !important;
  justify-content: center !important;
}

.mari-modal-panel > .shrink-0.flex.items-center.justify-between > button:hover {
  background: var(--win95-face) !important;
  color: var(--win95-text) !important;
}

.mari-modal-panel > .shrink-0.flex.items-center.justify-between > button:active {
  border-top-color: var(--win95-dark) !important;
  border-left-color: var(--win95-dark) !important;
  border-right-color: var(--win95-light) !important;
  border-bottom-color: var(--win95-light) !important;
  box-shadow:
    inset 1px 1px 0 var(--win95-shadow),
    inset -1px -1px 0 var(--win95-hilite) !important;
}

.mari-modal-panel > .shrink-0.flex.items-center.justify-between > button svg {
  width: 10px !important;
  height: 10px !important;
}

/* Form inputs inside dialogs need the standard Win95 sunken text-
 * control look. Engine often paints them with `bg-[var(--secondary)]
 * ring-1 ring-transparent focus:ring-...` which our token override
 * covers for bg, but the rounded ring needs explicit defeat. */
.mari-modal-panel input[type="text"],
.mari-modal-panel input[type="search"],
.mari-modal-panel input:not([type]),
.mari-modal-panel textarea,
.mari-modal-panel select,
.os-window input[type="text"],
.os-window input[type="search"],
.os-window input:not([type]),
.os-window textarea,
.os-window select {
  background: var(--win95-hilite) !important;
  color: var(--win95-text) !important;
  border-radius: 0 !important;
  --tw-ring-color: transparent !important;
}

/* ── Lucide icon weight ───────────────────────────────────────
 * Lucide-react icons render as thin single-weight stroked SVGs
 * (`stroke-width: 2` baseline). Win95 icons were chunky filled
 * pixel art. We can't replace the icons without JS DOM-swap, but
 * bumping the stroke and adding a high-contrast filter pushes them
 * visibly closer to period weight. The TopBar icon row gets the
 * heaviest treatment since that's the most-called-out surface. */
svg[class*="lucide"],
svg.lucide {
  stroke-width: 2.75 !important;
  shape-rendering: crispEdges;
}

[data-component="TopBar"] svg[class*="lucide"],
.mari-topbar svg[class*="lucide"],
.mari-sidebar-header svg[class*="lucide"],
.mari-right-panel-header svg[class*="lucide"] {
  stroke-width: 3 !important;
  filter: contrast(1.4) brightness(0.85);
}

/* Top bar buttons — group the icon row inside a Win95 toolbar tray
 * with a 1-px sunken separator at the bottom. Engine renders the
 * top-bar as `mari-topbar bg-[var(--card)]/80 backdrop-blur-sm` —
 * with backdrop-blur already killed, we just need a bottom border
 * to separate the toolbar from the chat area beneath. */
.mari-topbar,
[data-component="TopBar"] {
  background: var(--win95-face) !important;
  border-bottom: 1px solid var(--win95-shadow) !important;
}

/* ── Y2K decorative stars + glow effects ──────────────────
 * AppShell paints animated star glyphs at percentage positions
 * across the desktop background (`.y2k-star`, `.y2k-star-md`,
 * `.y2k-star-lg`) — pure modern decorative atmosphere. Win95 had
 * solid flat fills, no atmospheric effects. Hide them all. */
.y2k-star,
.y2k-star-md,
.y2k-star-lg {
  display: none !important;
}

/* Inline help-circle icons. The engine sprinkles `<HelpTooltip>`
 * everywhere (next to every Setting field label, every accordion
 * row). Win95 used the title-bar `?` for context help — never
 * inline next to every field. Hide them globally except inside
 * our own win95-titlebar (the close `?` etc.). */
svg.lucide-help-circle,
svg.lucide-circle-help,
svg[class*="lucide-help"] {
  display: none !important;
}

/* iOS/2010s-style pill toggles. The Connections panel TTS toggle
 * (and a few others) use a `role="switch"` button with a sliding
 * white circle. Reframe as a Win95 chunky button with the state
 * implied by a "X" or filled square. */
[role="switch"] {
  display: inline-flex !important;
  align-items: center;
  justify-content: center;
  width: 32px !important;
  height: 22px !important;
  padding: 0 !important;
  background: var(--win95-face) !important;
  border: 2px solid !important;
  border-top-color: var(--win95-light) !important;
  border-left-color: var(--win95-light) !important;
  border-right-color: var(--win95-dark) !important;
  border-bottom-color: var(--win95-dark) !important;
  border-radius: 0 !important;
  box-shadow:
    inset 1px 1px 0 var(--win95-hilite),
    inset -1px -1px 0 var(--win95-shadow) !important;
}

[role="switch"][aria-checked="true"] {
  border-top-color: var(--win95-dark) !important;
  border-left-color: var(--win95-dark) !important;
  border-right-color: var(--win95-light) !important;
  border-bottom-color: var(--win95-light) !important;
  box-shadow:
    inset 1px 1px 0 var(--win95-shadow),
    inset -1px -1px 0 var(--win95-hilite) !important;
}

[role="switch"]::after {
  content: "";
  display: block;
  width: 8px;
  height: 8px;
}

[role="switch"][aria-checked="true"]::after {
  background: var(--win95-text);
}

/* Hide the engine's sliding circle inside the switch */
[role="switch"] > * {
  display: none !important;
}

/* Top toolbar colored underline indicator. The TopBar buttons
 * each get a thin colored bottom-border line when their panel is
 * open. Win95 toggles used the pressed-bevel state instead — kill
 * the line, the button bevel already conveys state. */
.mari-topbar button > [class*="bg-"][class*="absolute"][class*="bottom-0"],
[data-component="TopBar"] button [class*="absolute"][class*="bottom-0"] {
  display: none !important;
}

/* "Danger Zone" callout in Advanced settings — engine paints as
 * `bg-red-500/X border-red-400/X` light-tinted panel with warning
 * triangle. Win95 used standard message-box dialogs; in-panel
 * tinted callouts are a GitHub/modern convention. Reframe as a
 * sunken Win95 group with a "WARNING" heading bar. */
[data-component="RightPanel"] [class*="bg-red-"][class*="border-red-"],
[data-component="RightPanel"] [class*="bg-rose-"][class*="border-rose-"] {
  background: var(--win95-face) !important;
  background-image: none !important;
  border: 2px solid !important;
  border-top-color: var(--win95-shadow) !important;
  border-left-color: var(--win95-shadow) !important;
  border-right-color: var(--win95-hilite) !important;
  border-bottom-color: var(--win95-hilite) !important;
  border-radius: 0 !important;
  color: var(--win95-text) !important;
}

/* Kill all transitions inside chat surfaces and panels. Win95 had
 * no hover/focus animations — every state change was instant. We
 * keep transitions on form inputs (focus rings) and modals (open/
 * close fade) since those provide useful feedback. */
[data-component="ChatSidebar"] *:not(input):not(textarea):not(.mari-modal-panel *),
[data-component^="ChatArea"] *:not(input):not(textarea):not(.mari-modal-panel *):not(.mari-message-typing *),
[data-component="RightPanel"] *:not(input):not(textarea):not(.mari-modal-panel *) {
  transition-property: none !important;
  transition-duration: 0s !important;
}

/* Modal backdrop dimming. Engine paints a `bg-black/60` scrim
 * behind every modal — Win95 never dimmed the background. Make
 * the scrim transparent so the rest of the UI stays at full
 * brightness when a modal opens. */
.mari-modal-backdrop,
.mari-modal *[class*="bg-black/"] {
  background: transparent !important;
}

/* ── Home-page text contrast ────────────────────────────────
 * Engine renders the home-page intro copy, mode-tile labels, FAQ
 * subtext, footer credits, etc. with `text-[var(--muted-foreground)]/N`
 * (Tailwind opacity-modifier syntax — compiles to a `color-mix` at
 * N% with transparent). Under our `--muted-foreground` = #808080,
 * mixed against `#c0c0c0` at 50–70%, the result is barely visible.
 *
 * Force solid Win95 text (black) for all foreground/muted text in
 * the EmptyState and the FAQ. The hierarchy gets flatter but stays
 * Win95-period: real Win95 dialogs used near-black for body text,
 * with visual hierarchy carried by font size and bold rather than
 * by color alpha. */
[data-component="ChatArea.EmptyState"] [class*="text-[var(--muted-foreground)"],
[data-component="ChatArea.EmptyState"] [class*="text-[var(--foreground)"],
[data-component="ChatArea.EmptyState"] [class*="text-foreground"],
[data-component="ChatArea.EmptyState"] [class*="text-white"]:not(.mari-message-bubble *) {
  color: var(--win95-text) !important;
  opacity: 1 !important;
}

/* Mode-tile icons (Conversation / Roleplay / Game) — these are
 * Lucide SVGs that inherit color from the parent. With the parent
 * pinned to win95-text, they should render solid black. Defensive
 * rule for any direct icon coloring. */
[data-component="ChatArea.EmptyState"] .card-3d-tilt svg,
[data-component="ChatArea.EmptyState"] button svg {
  color: var(--win95-text) !important;
  stroke: var(--win95-text) !important;
}

/* ── Decorative sparkles (✦ ✧ ✨) ──────────────────────────
 * The engine sprinkles diamond/sparkle glyphs around branding
 * (`✧ Marinara Engine ✧`, `✦ PROFESSOR MARI`, `✧ Chats`, etc.).
 * Pure 2020s "AI-vibes" decoration; period-incorrect for Win95.
 * Hide them via an `::before` rule that sets the line-height to
 * collapse the character entirely. Easier path: replace via JS,
 * but pure-CSS works for ASCII-encoded glyphs. */
.retro-glow-text,
[data-component="ChatArea.EmptyState"] h1,
[data-component="ChatArea.EmptyState"] h2,
[data-component="ChatArea.EmptyState"] h3 {
  font-variant-ligatures: none;
}

/* Settings / Right panel title bar — engine renders the right panel
 * with a flat header row (gear icon + "Settings" text + close X).
 * No blue Win95 titlebar. Add one via the panel's existing
 * `.mari-right-panel-header` class. */
.mari-right-panel-header,
[data-component="RightPanel"] > div:first-child {
  background: linear-gradient(
    to right,
    var(--win95-title-active-1) 0%,
    var(--win95-title-active-2) 100%
  ) !important;
  color: var(--win95-hilite) !important;
  height: 22px !important;
  min-height: 22px !important;
  padding: 2px 4px !important;
  font-family: var(--font-y2k);
  font-size: 11px;
  font-weight: 700;
}

.mari-right-panel-header *,
[data-component="RightPanel"] > div:first-child * {
  color: var(--win95-hilite) !important;
}

/* Footer hyperlinks on the home page (engine renders as
 * underlined `<a>` with a subtle hover color shift). Repaint as
 * classic Win95 navy underlined links. */
[data-component="ChatArea.EmptyState"] a {
  color: var(--win95-title-active-1) !important;
  text-decoration: underline !important;
  text-decoration-color: var(--win95-title-active-1) !important;
}

[data-component="ChatArea.EmptyState"] a:visited {
  color: #800080 !important; /* Win95 visited-link purple */
}

[data-component="ChatArea.EmptyState"] a:hover {
  color: var(--win95-title-active-2) !important;
  background: transparent !important;
}

/* Notched Win95-style settings tabs. Engine renders the tab row
 * with `.border-b border-[var(--sidebar-border)]`. We already paint
 * each tab as a Win95 button; this rule connects the active tab to
 * the panel below by hiding its bottom border (same trick real
 * Win95 tab dialogs use to show "this tab is in front"). */
[data-component="RightPanel"] .border-b > button:has(> span[class*="bg-[var(--primary)]"]) {
  border-bottom-color: var(--win95-face) !important;
  margin-bottom: -2px;
  z-index: 1;
}

/* Sort dropdown arrow. Engine renders the sort `<select>` with a
 * Lucide `ArrowUpDown` icon overlay (`↕`). Win95 comboboxes use a
 * downward-triangle button on the right. CSS `appearance: none`
 * already strips the native arrow; my generic `select` rule paints
 * the sunken bevel. The `<ArrowUpDown>` icon is a separate sibling
 * we can replace via `::after` content on the wrapper. */
[data-component="ChatSidebar"] select + svg[class*="lucide"] {
  display: none !important;
}

[data-component="ChatSidebar"] .relative:has(> select)::after {
  content: "▼";
  position: absolute;
  right: 4px;
  top: 50%;
  transform: translateY(-50%);
  font-size: 9px;
  color: var(--win95-text);
  pointer-events: none;
  background: var(--win95-face);
  border: 1px solid;
  border-top-color: var(--win95-light);
  border-left-color: var(--win95-light);
  border-right-color: var(--win95-dark);
  border-bottom-color: var(--win95-dark);
  width: 16px;
  height: 16px;
  display: flex;
  align-items: center;
  justify-content: center;
}

/* "Active" status footer green dot — already squared via the
 * presence-LED rule above, but also kill any animation/glow that
 * might still pulse on it. */
[data-component="ChatSidebar"] [class*="bg-green-500"] {
  background: #00aa00 !important; /* True Win95 LED green, no glow */
  animation: none !important;
}

/* Title-bar button glyphs (`_`, `□`, `×`). My current Win95 chrome
 * paints them in the Marlett font when available, falling back to
 * Unicode. Force a chunkier system font and hard pixel rendering. */
.win95-titlebar-btn {
  font-family: "Marlett", "Microsoft Sans Serif", "MS Sans Serif", monospace !important;
  font-weight: 700 !important;
  font-size: 10px !important;
  text-rendering: geometricPrecision !important;
  -webkit-font-smoothing: none !important;
}

/* Catch-all: any `<button>` or `<a>` rendered as a button that's
 * still rounded somewhere we missed. Pure-Win95 components have
 * zero border-radius. */
[data-component^="ChatArea"] button,
[data-component^="ChatArea"] [role="button"],
[data-component="ChatSidebar"] button,
[data-component="ChatSidebar"] [role="button"],
[data-component="RightPanel"] button,
[data-component="RightPanel"] [role="button"] {
  border-radius: 0 !important;
}

/* ── Glass / frosted panels ─────────────────────────────────
 * `.glass` and `.glass-strong` are y2k effect classes used on the
 * top toolbar, sidebar header, right panel header, and the home
 * page FAQ card. They paint a peach/pink/blue gradient + blur.
 * Defeat completely: flat Win95 face, no gradient, no blur. */
.glass,
.glass-strong {
  background: var(--win95-face) !important;
  background-image: none !important;
  border: 0 !important;
  box-shadow: none !important;
  backdrop-filter: none !important;
  -webkit-backdrop-filter: none !important;
  border-radius: 0 !important;
}

/* ── Tailwind arbitrary-value gradients ─────────────────────
 * The HomeFaq card and its sub-panels use Tailwind's
 * `bg-[linear-gradient(...)]` / `bg-[radial-gradient(...)]`
 * arbitrary-value syntax — my earlier `[class*="bg-gradient-to"]`
 * rule didn't catch these because the class name format is different.
 * Catch all gradient-ish arbitrary backgrounds across the home page,
 * chat surfaces, and right panel. */
[data-component^="ChatArea"] [class*="bg-[linear-gradient"],
[data-component^="ChatArea"] [class*="bg-[radial-gradient"],
[data-component="RightPanel"] [class*="bg-[linear-gradient"],
[data-component="RightPanel"] [class*="bg-[radial-gradient"],
[data-component="ChatSidebar"] [class*="bg-[linear-gradient"],
[data-component="ChatSidebar"] [class*="bg-[radial-gradient"] {
  background: var(--win95-face) !important;
  background-image: none !important;
  box-shadow: none !important;
}

/* Inline-style gradients (RecentChats mode dots set
 * `style={{ background: linear-gradient(...) }}`, character/preset
 * card icons same pattern). Catch via attribute substring match
 * on the `style` attribute. Scoped to chat-area surfaces + panels
 * so we don't disturb anything outside our theme reach. The
 * ChatSidebar entry covers the GameSetupWizard mode-icon backdrop
 * (a pink linear-gradient set inline on the icon container of the
 * "New Game" / "Visual Novel" / "Game" rows). */
[data-component^="ChatArea"] [style*="linear-gradient"],
[data-component^="ChatArea"] [style*="radial-gradient"],
[data-component="RightPanel"] [style*="linear-gradient"],
[data-component="RightPanel"] [style*="radial-gradient"],
[data-component="ChatSidebar"] [style*="linear-gradient"],
[data-component="ChatSidebar"] [style*="radial-gradient"] {
  background: var(--win95-face) !important;
  background-image: none !important;
}

/* ── Flatten Tailwind accent-color utilities on chrome ────────
 * Various surfaces still leak through accent-colored icons and
 * badges via Tailwind `text-{color}-{shade}` and `bg-{color}-{shade}`
 * utilities — Personas empty-state (green User), Connections
 * selected badge (blue circle + white check), Agents category
 * icons (orange Regex, teal Writer), Browser stat icons (red
 * Download/Comment counts), etc. Win95 chrome was essentially
 * monochrome — the only accent colors were #000080 selection
 * blue and #aa0000 destructive red. Flatten everything else
 * inside our chrome scope to var(--win95-text)/var(--win95-face).
 * Semantic Tailwind tokens (`text-foreground`, `text-muted`,
 * `bg-card`, etc) don't match these substring patterns because
 * they have no `-{shade}` digit suffix, so this rule leaves them
 * alone — they're already remapped via the :root CSS vars. */
:where(
  [data-component="ChatSidebar"],
  [data-component="RightPanel"],
  [data-component^="ChatArea"],
  [data-component="TopBar"],
  .mari-modal-panel,
  .os-window
) :is(
  [class*="text-amber-"],
  [class*="text-orange-"],
  [class*="text-red-"],
  [class*="text-rose-"],
  [class*="text-pink-"],
  [class*="text-purple-"],
  [class*="text-fuchsia-"],
  [class*="text-violet-"],
  [class*="text-indigo-"],
  [class*="text-blue-"],
  [class*="text-sky-"],
  [class*="text-cyan-"],
  [class*="text-teal-"],
  [class*="text-emerald-"],
  [class*="text-green-"],
  [class*="text-lime-"],
  [class*="text-yellow-"]
) {
  color: var(--win95-text) !important;
}

/* For background-color utilities the substring match needs to
 * exclude Tailwind variants — `hover:bg-pink-500` shares the
 * `bg-pink-` substring with the base utility, but only sets the
 * bg on :hover. Forcing it always-on permanently activates the
 * hover bg, which made the New button glow navy and would do
 * the same to every other accent-hover element. The two-pronged
 * `[class^="bg-..."]` (className starts with) plus
 * `[class*=" bg-..."]` (preceded by a space, never `:`) catches
 * the base utility wherever it sits in the className list while
 * leaving variant-prefixed classes alone. */
:where(
  [data-component="ChatSidebar"],
  [data-component="RightPanel"],
  [data-component^="ChatArea"],
  [data-component="TopBar"],
  .mari-modal-panel,
  .os-window
) :is(
  [class^="bg-amber-"],   [class*=" bg-amber-"],
  [class^="bg-orange-"],  [class*=" bg-orange-"],
  [class^="bg-red-"],     [class*=" bg-red-"],
  [class^="bg-rose-"],    [class*=" bg-rose-"],
  [class^="bg-pink-"],    [class*=" bg-pink-"],
  [class^="bg-purple-"],  [class*=" bg-purple-"],
  [class^="bg-fuchsia-"], [class*=" bg-fuchsia-"],
  [class^="bg-violet-"],  [class*=" bg-violet-"],
  [class^="bg-indigo-"],  [class*=" bg-indigo-"],
  [class^="bg-blue-"],    [class*=" bg-blue-"],
  [class^="bg-sky-"],     [class*=" bg-sky-"],
  [class^="bg-cyan-"],    [class*=" bg-cyan-"],
  [class^="bg-teal-"],    [class*=" bg-teal-"],
  [class^="bg-emerald-"], [class*=" bg-emerald-"],
  [class^="bg-green-"],   [class*=" bg-green-"],
  [class^="bg-lime-"],    [class*=" bg-lime-"],
  [class^="bg-yellow-"],  [class*=" bg-yellow-"]
) {
  background: var(--win95-face) !important;
  background-color: var(--win95-face) !important;
  background-image: none !important;
}

/* ── Unscoped avatar squaring + glow defeat ───────────────────
 * The earlier scoped pixelation only catches ChatSidebar +
 * ChatArea avatars. CharacterEditor / LorebookEditor / Persona
 * editor mount in their own surfaces and re-show round avatars
 * with `box-shadow: 0 0 ...` glows. Square + de-glow any
 * `<img>` whose parent context applies `rounded-{full,2xl,xl}`
 * — covers all editors, modals, panels uniformly.
 *
 * Note: explicitly NOT scoping to chrome data-components so
 * editor surfaces inherit the same treatment. Carve-out only
 * for chat-content images so user-uploaded inline images keep
 * the engine's intended display. */
img[class*="rounded-full"]:not(.mari-message-content img),
img[class*="rounded-2xl"]:not(.mari-message-content img),
img[class*="rounded-xl"]:not(.mari-message-content img) {
  border-radius: 0 !important;
  image-rendering: pixelated;
  image-rendering: -moz-crisp-edges;
  filter: saturate(0.6) contrast(1.1);
  box-shadow: none !important;
}

/* Avatar parent containers — engine wraps `<img>` in
 * `<div class="rounded-full ... shadow-... ring-...">` to apply
 * the round mask + glow. Square the wrapper too and kill any
 * shadow/ring that would render around the squared photo. */
div[class*="rounded-full"]:not(.mari-message-content *):not(.win95-skip):has(> img),
div[class*="rounded-full"]:not(.mari-message-content *):not(.win95-skip):has(> div[class*="rounded-full"]) {
  border-radius: 0 !important;
  box-shadow: none !important;
  --tw-shadow: 0 0 #0000 !important;
  --tw-ring-shadow: 0 0 #0000 !important;
  --tw-ring-color: transparent !important;
}

/* ── Inline-style color flatten (character name preview etc) ──
 * The engine's character editor renders name/dialogue color
 * previews via `style={{ color: character.nameColor }}` — defaults
 * to a pink/rose hex that bleeds through our class-based color
 * flatten. Force inline-style color to win95-text on any element
 * that's not chat content. Also covers stray `style="background:
 * #..."` swatches outside the explicit gradient defeat. */
[style*="color:"]:not(.mari-message-content *):not(.mari-message-bubble *):not(svg):not([style*="background"]) {
  color: var(--win95-text) !important;
}

/* ── Chat surface background reset ───────────────────────────
 * Engine often layers `bg-[var(--background)]/X` or similar
 * semi-transparent tints on the chat surface that read as a
 * greenish/warmer tint over our flat #c0c0c0 face. Force the
 * chat surface itself + its immediate scroll wrapper to plain
 * Win95 face — no gradients, no transparent overlays. */
.mari-chat-area,
.rpg-chat-area,
[data-component="ChatArea.Conversation"],
[data-component="ChatArea.Roleplay"],
[data-component="ChatArea.Conversation"] > div:not([data-win95-chrome]),
[data-component="ChatArea.Roleplay"] > div:not([data-win95-chrome]) {
  background: var(--win95-face) !important;
  background-color: var(--win95-face) !important;
  background-image: none !important;
  backdrop-filter: none !important;
  -webkit-backdrop-filter: none !important;
}

/* ── Unscoped placeholder-gradient defeat ────────────────────
 * No-image character cards in the Library / Browser render a
 * pink-to-blue gradient placeholder via `bg-gradient-to-br
 * from-pink-200 to-sky-200` (or similar). The earlier scoped
 * gradient flatten misses these because the Library mounts in
 * a context not in our chrome scope list. Apply the flatten
 * unscoped — exclude only chat user-bubble (which intentionally
 * uses a navy-gradient look that we already flattened separately
 * to a flat solid). */
[class*="bg-gradient-to"]:not(.mari-message-bubble):not(.mari-message-content *) {
  background-image: none !important;
  background: var(--win95-face) !important;
}

/* ── Unscoped muted-text defeat ──────────────────────────────
 * `text-foreground/X` and `text-muted-foreground` etc. produce
 * 30–60% black on the dark Y2K theme — illegible on Win95 grey.
 * Unscoped force to full opacity black, exclude chat content. */
[class*="text-foreground/"]:not(.mari-message-content *):not(.mari-message-bubble *),
[class*="text-muted-foreground"]:not(.mari-message-content *):not(.mari-message-bubble *) {
  color: var(--win95-text) !important;
  opacity: 1 !important;
}

/* ── Square the rounded-full badges & buttons ───────────────
 * Engine uses `rounded-full` for tag pills (assistant, guide,
 * etc), avatar containers (already squared via image rule), and
 * some action buttons. Square the badges + general containers
 * but skip <img> (avatar pixelation rule already squares those)
 * and `.win95-skip` (our own decorative buttons). */
[class*="rounded-full"]:not(img):not(.win95-skip):not(.mari-message-content *):not(.mari-message-bubble *) {
  border-radius: 0 !important;
}

/* ── Last-resort accent flatten (unscoped) ────────────────────
 * The :where(...) scope above misses elements that mount outside
 * our predeclared chrome surfaces (e.g. ChubAI character browser
 * cards rendered inside a modal whose className signature changes
 * per breakpoint, lorebook editor's amber Enabled toggle, presets
 * panel cards). Apply text-pink/rose/red/amber/yellow/orange flat
 * globally to anything NOT inside `.mari-message-content` (chat
 * body) or `.mari-message-bubble` (so user message bubbles keep
 * white text). The destructive red (`text-[var(--destructive)]`)
 * uses arbitrary-value syntax so it doesn't match these named-
 * color patterns and stays as the Win95 warning red. */
[class*="text-pink-"]:not(.mari-message-content *):not(.mari-message-bubble *),
[class*="text-rose-"]:not(.mari-message-content *):not(.mari-message-bubble *),
[class*="text-red-"]:not(.mari-message-content *):not(.mari-message-bubble *),
[class*="text-amber-"]:not(.mari-message-content *):not(.mari-message-bubble *),
[class*="text-orange-"]:not(.mari-message-content *):not(.mari-message-bubble *),
[class*="text-yellow-"]:not(.mari-message-content *):not(.mari-message-bubble *) {
  color: var(--win95-text) !important;
}

/* ── Muted-text contrast boost ────────────────────────────────
 * Engine subtitles use `text-foreground/40` / `text-foreground/50`
 * etc — fine on the dark Y2K theme but illegible on Win95's
 * #c0c0c0 face. Force full opacity on chrome-side muted text so
 * subtitles in Presets, Agents, Lorebook entries, etc. read as
 * the same #000 as the rest of the chrome. Scope avoids chat
 * body so message-content opacity tokens stay user-styled. */
:where(
  [data-component="ChatSidebar"],
  [data-component="RightPanel"],
  [data-component="TopBar"],
  .mari-modal-panel,
  .os-window
) [class*="text-foreground/"]:not(.mari-message-content *) {
  color: var(--win95-text) !important;
  opacity: 1 !important;
}

/* CRITICAL: Engine wraps lists in `.stagger-children` which uses a
 * CSS keyframe to fade children in from opacity:0. Killing all
 * animations (rule below) freezes them at opacity:0 — characters,
 * presets, agents, and other listed items VANISH. Force opacity:1
 * + reset transform so list children stay visible regardless of
 * the animation's frozen state. Place this BEFORE the animation
 * defeat so source order is irrelevant — cascade wins on
 * specificity (0,1,1) > (0,1,0). */
.stagger-children > * {
  opacity: 1 !important;
  transform: none !important;
  animation: none !important;
}

/* ── Defeat hover/scale/floating animations ───────────────────
 * Engine sprinkles `transition-all`, `active:scale-90`,
 * `hover:scale-105`, `animate-pulse` etc. These soft-elastic
 * effects feel modern; Win95 controls were strictly state-snap.
 * Kill transitions/animations and identity transforms inside
 * chrome surfaces. Scoped to chrome only so chat content
 * (typing dots, streaming animations) keeps its motion. */
:where(
  [data-component="ChatSidebar"],
  [data-component="RightPanel"],
  [data-component="TopBar"],
  .mari-modal-panel,
  .os-window
) [class*="transition-"]:not(.mari-message-content *),
:where(
  [data-component="ChatSidebar"],
  [data-component="RightPanel"],
  [data-component="TopBar"],
  .mari-modal-panel,
  .os-window
) [class*="animate-"]:not(.mari-message-content *) {
  transition: none !important;
  animation: none !important;
}
:where(
  [data-component="ChatSidebar"],
  [data-component="RightPanel"],
  [data-component="TopBar"],
  .mari-modal-panel,
  .os-window
) [class*="hover:scale"]:not(.mari-message-content *):hover,
:where(
  [data-component="ChatSidebar"],
  [data-component="RightPanel"],
  [data-component="TopBar"],
  .mari-modal-panel,
  .os-window
) [class*="active:scale"]:not(.mari-message-content *):active,
:where(
  [data-component="ChatSidebar"],
  [data-component="RightPanel"],
  [data-component="TopBar"],
  .mari-modal-panel,
  .os-window
) [class*="group-active:scale"]:not(.mari-message-content *) {
  transform: none !important;
  scale: 1 !important;
}

/* ── Search input padding compensation ────────────────────────
 * Our pixel-art magnifier swap takes more horizontal real estate
 * inside its 16x16 viewBox than Lucide's narrow circle, so the
 * placeholder text on inputs with tight `pl-3`/`pl-7` overlaps
 * the icon (visible on Search characters / Search presets).
 * Bump padding-left for any text input whose placeholder begins
 * "Search " — covers the engine's search inputs without touching
 * unrelated text fields. */
input[type="text"][placeholder^="Search "],
input[type="search"][placeholder^="Search "] {
  padding-left: 2.25rem !important;
}

/* SVG `fill` attribute set via inline style — common on category
 * icons that the Tailwind class flatten above misses (some icons
 * carry the color on `style="color: #..."` directly rather than
 * via a utility class). Force currentColor inheritance. */
:where(
  [data-component="ChatSidebar"],
  [data-component="RightPanel"],
  [data-component^="ChatArea"],
  .mari-modal-panel,
  .os-window
) svg[style*="color"] {
  color: var(--win95-text) !important;
}

/* Tailwind arbitrary CSS-variable tints — `bg-[var(--TOKEN)]/X`,
 * `border-[var(--TOKEN)]/X`, etc. The named-color flatten above
 * doesn't catch these because they don't have a `bg-{name}-{shade}`
 * shape. Two cases worth handling explicitly:
 *   sidebar-accent — used by ConnectionsPanel for the selected
 *     connection row (`bg-[var(--sidebar-accent)]/50`); the /50
 *     opacity makes our navy + grey field mix to a muddy purple.
 *     Force full opacity navy with white text — the canonical
 *     Win95 selection look.
 *   destructive — used by SettingsPanel "Danger Zone" for the
 *     selected scope row (`bg-[var(--destructive)]/10`) and
 *     border (`border-[var(--destructive)]/30`); the low alpha
 *     reads as peach. Flatten to the standard Win95 face + a
 *     grey shadow border. The destructive RED on `text-` /
 *     icon stays — that's the Win95-authentic warning color.
 *   primary — used by some active-state buttons + tab underlines.
 *     Re-snap to the active titlebar blue. */
[class^="bg-[var(--sidebar-accent)]"],
[class*=" bg-[var(--sidebar-accent)]"] {
  background-color: var(--win95-title-active-1) !important;
  background-image: none !important;
  color: var(--win95-hilite) !important;
}
[class^="bg-[var(--sidebar-accent)]"] *,
[class*=" bg-[var(--sidebar-accent)]"] * {
  color: var(--win95-hilite) !important;
}

[class^="bg-[var(--destructive)]"],
[class*=" bg-[var(--destructive)]"] {
  background-color: var(--win95-face) !important;
  background-image: none !important;
}
[class^="border-[var(--destructive)]"],
[class*=" border-[var(--destructive)]"] {
  border-color: var(--win95-shadow) !important;
}

[class^="bg-[var(--primary)]"],
[class*=" bg-[var(--primary)]"] {
  background-color: var(--win95-title-active-1) !important;
  background-image: none !important;
  color: var(--win95-hilite) !important;
}
/* When `bg-[var(--primary)]/X` flags a row as selected (e.g. the
 * Characters / Personas / Lorebooks panel selected entries), the
 * navy-on-grey override above paints the bg, but descendant text
 * rules still leave the title/subtitle as black — illegible
 * against the navy. Force white on all descendants for any
 * primary-bg container so the selection contrast matches the
 * canonical Win95 selection look. */
[class^="bg-[var(--primary)]"] *,
[class*=" bg-[var(--primary)]"] * {
  color: var(--win95-hilite) !important;
}

/* Tailwind gradient utilities (`bg-gradient-to-{br|tr|...}` paired
 * with `from-{color}-{shade}` and `to-{color}-{shade}`). The
 * direction utility carries no color but defines the gradient
 * scaffold; killing `background-image` on it nukes any from/to
 * color stops the engine sets, regardless of which Tailwind palette
 * names they used. Used heavily in ConnectionsPanel for provider
 * badges and category tiles. */
:where(
  [data-component="ChatSidebar"],
  [data-component="RightPanel"],
  [data-component^="ChatArea"],
  [data-component="TopBar"],
  .mari-modal-panel,
  .os-window
) :is(
  [class^="bg-gradient-to"],
  [class*=" bg-gradient-to"]
) {
  background-image: none !important;
  background-color: var(--win95-face) !important;
}

/* RecentChats pills on the home page. Engine renders as `<button
 * class="rounded-lg border border-[var(--border)]/50 bg-[var(--card)]/50
 * px-2 py-1.5 ...">` with rounded avatar + colored mode-dot badge.
 * Reframe as raised Win95 buttons + square avatars. */
[data-component="ChatArea.EmptyState"] button[class*="rounded-lg"][class*="border"][class*="bg-[var(--card)]"] {
  border-radius: 0 !important;
  border: 2px solid !important;
  border-top-color: var(--win95-light) !important;
  border-left-color: var(--win95-light) !important;
  border-right-color: var(--win95-dark) !important;
  border-bottom-color: var(--win95-dark) !important;
  box-shadow:
    inset 1px 1px 0 var(--win95-hilite),
    inset -1px -1px 0 var(--win95-shadow) !important;
  background: var(--win95-face) !important;
}

/* RecentChats avatars and mode-dot indicators (rounded-md squares
 * inside the recent-chat pill — both image and gradient-fallback
 * tiles). Square them and let the gradient kill above flatten. */
[data-component="ChatArea.EmptyState"] img.rounded-md,
[data-component="ChatArea.EmptyState"] div.rounded-md,
[data-component="ChatArea.EmptyState"] [class*="rounded-md"] {
  border-radius: 0 !important;
}

/* Visual Style cards in Settings → Appearance.
 *   <button class="flex flex-col items-start gap-1 rounded-lg border p-3 ..."
 *   active: border-[var(--primary)] bg-[var(--primary)]/10 ring-1 ring-[var(--primary)]
 * Square + bevel as Win95 buttons; active card uses pressed bevel. */
[data-component="RightPanel"] button.rounded-lg.border.p-3,
[data-component="RightPanel"] button[class*="rounded-lg"][class*="border"][class*="p-3"] {
  border-radius: 0 !important;
  border: 2px solid !important;
  border-top-color: var(--win95-light) !important;
  border-left-color: var(--win95-light) !important;
  border-right-color: var(--win95-dark) !important;
  border-bottom-color: var(--win95-dark) !important;
  box-shadow:
    inset 1px 1px 0 var(--win95-hilite),
    inset -1px -1px 0 var(--win95-shadow) !important;
  background: var(--win95-face) !important;
  color: var(--win95-text) !important;
  --tw-ring-color: transparent !important;
}

[data-component="RightPanel"] button[class*="rounded-lg"][class*="border-[var(--primary)]"][class*="bg-[var(--primary)]"] {
  border-top-color: var(--win95-dark) !important;
  border-left-color: var(--win95-dark) !important;
  border-right-color: var(--win95-light) !important;
  border-bottom-color: var(--win95-light) !important;
  box-shadow:
    inset 1px 1px 0 var(--win95-shadow),
    inset -1px -1px 0 var(--win95-hilite) !important;
}

/* FAQ rounded pills inside the expanded hero ("PROFESSOR MARI"
 * label, "N answers" badge, the Q&A "Before You Post A Bug" group,
 * and any other `rounded-full bg-black/X border` chips). Reframe as
 * monochrome Win95 chips. */
[data-component="ChatArea.EmptyState"] [class*="rounded-full"][class*="bg-black"],
[data-component="ChatArea.EmptyState"] [class*="rounded-full"][class*="border"] {
  background: var(--win95-face) !important;
  background-image: none !important;
  border-radius: 0 !important;
  border: 1px solid var(--win95-shadow) !important;
  color: var(--win95-text) !important;
  text-shadow: none !important;
}

/* Date / day divider hairline in the conversation message scroll
 * (the centered "Yesterday" / "Today" text with a thin line either
 * side). Engine renders the lines as `<span class="h-px flex-1
 * bg-[var(--border)]/40">`. Reframe as a 2-px Win95 inset rule. */
.mari-messages-scroll .h-px[class*="bg-[var(--border)"],
.mari-chat-area .h-px[class*="bg-[var(--border)"] {
  height: 0 !important;
  border-top: 1px solid var(--win95-shadow) !important;
  border-bottom: 1px solid var(--win95-hilite) !important;
  background: none !important;
}

/* ── Range sliders ─────────────────────────────────────────────
 * Win95 trackbar: chunky rectangular thumb with sunken track. The
 * default `<input type="range">` renders modern HTML5 styling which
 * sticks out as anachronistic. */
input[type="range"] {
  -webkit-appearance: none !important;
  appearance: none !important;
  background: transparent !important;
  height: 22px;
  padding: 0;
  border: 0 !important;
  box-shadow: none !important;
}

input[type="range"]::-webkit-slider-runnable-track {
  height: 4px;
  background: var(--win95-shadow);
  border: 1px solid;
  border-top-color: var(--win95-dark);
  border-left-color: var(--win95-dark);
  border-right-color: var(--win95-hilite);
  border-bottom-color: var(--win95-hilite);
}

input[type="range"]::-moz-range-track {
  height: 4px;
  background: var(--win95-shadow);
  border: 1px solid;
  border-top-color: var(--win95-dark);
  border-left-color: var(--win95-dark);
  border-right-color: var(--win95-hilite);
  border-bottom-color: var(--win95-hilite);
}

input[type="range"]::-webkit-slider-thumb {
  -webkit-appearance: none;
  appearance: none;
  width: 12px;
  height: 22px;
  background: var(--win95-face);
  border: 2px solid;
  border-top-color: var(--win95-light);
  border-left-color: var(--win95-light);
  border-right-color: var(--win95-dark);
  border-bottom-color: var(--win95-dark);
  box-shadow:
    inset 1px 1px 0 var(--win95-hilite),
    inset -1px -1px 0 var(--win95-shadow);
  border-radius: 0;
  cursor: default;
  margin-top: -10px;
}

input[type="range"]::-moz-range-thumb {
  width: 12px;
  height: 22px;
  background: var(--win95-face);
  border: 2px solid;
  border-top-color: var(--win95-light);
  border-left-color: var(--win95-light);
  border-right-color: var(--win95-dark);
  border-bottom-color: var(--win95-dark);
  box-shadow:
    inset 1px 1px 0 var(--win95-hilite),
    inset -1px -1px 0 var(--win95-shadow);
  border-radius: 0;
  cursor: default;
}

/* ── Color picker ─────────────────────────────────────────────
 * Native `<input type="color">` shows a modern browser swatch — wrap
 * it in a Win95 sunken bevel so the swatch reads as a Win95 control.
 * Clicking still opens the browser's native picker dialog (which we
 * can't override without JS), but at least the trigger looks period. */
input[type="color"] {
  -webkit-appearance: none !important;
  appearance: none !important;
  width: 36px !important;
  height: 22px !important;
  background: transparent !important;
  border: 2px solid !important;
  border-top-color: var(--win95-shadow) !important;
  border-left-color: var(--win95-shadow) !important;
  border-right-color: var(--win95-hilite) !important;
  border-bottom-color: var(--win95-hilite) !important;
  box-shadow:
    inset 1px 1px 0 var(--win95-dark),
    inset -1px -1px 0 var(--win95-light) !important;
  border-radius: 0 !important;
  padding: 1px !important;
  cursor: default;
}

input[type="color"]::-webkit-color-swatch-wrapper {
  padding: 0;
}

input[type="color"]::-webkit-color-swatch {
  border: 1px solid var(--win95-text);
  border-radius: 0;
}

input[type="color"]::-moz-color-swatch {
  border: 1px solid var(--win95-text);
  border-radius: 0;
}

/* ── Presence dots / status LEDs ──────────────────────────────
 * Engine paints `bg-green-500` / `bg-yellow-500` / `bg-red-500`
 * `rounded-full` dots with subtle glow shadows for online/idle/dnd
 * presence. Win95 had no presence concept and certainly no glowing
 * anti-aliased circles. Keep the color (it's a meaningful signal)
 * but flatten to a hard 6×6 square LED with no glow + a 1-px black
 * outline for that authentic 32-bit-icon LED look. */
[class*="bg-green-500"][class*="rounded-full"],
[class*="bg-yellow-500"][class*="rounded-full"],
[class*="bg-red-500"][class*="rounded-full"],
[class*="bg-gray-400"][class*="rounded-full"] {
  border-radius: 0 !important;
  box-shadow: none !important;
  filter: none !important;
  outline: 1px solid var(--win95-text);
}

/* ── Home page (`[data-component="ChatArea.EmptyState"]`) ──────
 * Marinara branding lives here: the gradient pasta-bowl logo with
 * its `rounded-2xl shadow-xl shadow-orange-500/20 animate-pulse-ring
 * bunny-glow` container, the "✧ Marinara Engine ✧" wordmark with
 * `retro-glow-text`, and three QuickStartCard mode tiles with inline
 * gradient swatch backgrounds. Period-incorrect across the board.
 * Square the logo container, kill the glow + animation, flatten the
 * wordmark, and pin mode-tile icon swatches to Win95 face. */
[data-component="ChatArea.EmptyState"] [class*="rounded-2xl"][class*="shadow"] {
  border-radius: 0 !important;
  box-shadow: none !important;
  animation: none !important;
}

[data-component="ChatArea.EmptyState"] [class*="rounded-2xl"][class*="shadow"] img {
  filter: grayscale(0.7) contrast(0.85);
}

[data-component="ChatArea.EmptyState"] .retro-glow-text {
  text-shadow: none !important;
  color: var(--win95-text) !important;
  background: none !important;
  background-image: none !important;
  -webkit-text-fill-color: var(--win95-text) !important;
  background-clip: border-box !important;
  -webkit-background-clip: border-box !important;
}

/* QuickStartCard (the three mode tiles — Conversation / Roleplay /
 * Game). The card itself uses `rounded-xl border-2 bg-[var(--card)]
 * card-3d-tilt btn-scanlines` and a hover lift; the icon swatch
 * inside has an inline gradient bg passed as a prop. Reframe the card
 * as a plain Win95 raised button and flatten the gradient swatch. */
[data-component="ChatArea.EmptyState"] .card-3d-tilt {
  border-radius: 0 !important;
  border: 2px solid !important;
  border-top-color: var(--win95-light) !important;
  border-left-color: var(--win95-light) !important;
  border-right-color: var(--win95-dark) !important;
  border-bottom-color: var(--win95-dark) !important;
  box-shadow:
    inset 1px 1px 0 var(--win95-hilite),
    inset -1px -1px 0 var(--win95-shadow) !important;
  background: var(--win95-face) !important;
  transform: none !important;
}

[data-component="ChatArea.EmptyState"] .card-3d-tilt:active,
[data-component="ChatArea.EmptyState"] .card-3d-tilt:hover {
  transform: none !important;
  border-top-color: var(--win95-light) !important;
  border-left-color: var(--win95-light) !important;
  border-right-color: var(--win95-dark) !important;
  border-bottom-color: var(--win95-dark) !important;
}

[data-component="ChatArea.EmptyState"] .card-3d-tilt > div[style*="background"],
[data-component="ChatArea.EmptyState"] .card-3d-tilt > div[style*="linear-gradient"] {
  background: var(--win95-face) !important;
  background-image: none !important;
  border: 1px solid var(--win95-shadow) !important;
  border-radius: 0 !important;
  box-shadow: none !important;
}

[data-component="ChatArea.EmptyState"] .btn-scanlines::after,
[data-component="ChatArea.EmptyState"] .btn-scanlines::before {
  display: none !important;
}

/* HomeFaq card and its inner badges/avatars. The card root has a
 * rounded pill style with shadow + a circular Professor Mari avatar
 * + a small "N answers" rounded-full badge. Flatten everything. */
[data-component="ChatArea.EmptyState"] [class*="rounded-2xl"],
[data-component="ChatArea.EmptyState"] [class*="rounded-3xl"],
[data-component="ChatArea.EmptyState"] [class*="rounded-xl"],
[data-component="ChatArea.EmptyState"] [class*="rounded-lg"],
[data-component="ChatArea.EmptyState"] [class*="rounded-md"],
[data-component="ChatArea.EmptyState"] [class*="rounded-full"],
[data-component="ChatArea.EmptyState"] [class*="rounded-["] {
  border-radius: 0 !important;
}

[data-component="ChatArea.EmptyState"] [class*="shadow-lg"],
[data-component="ChatArea.EmptyState"] [class*="shadow-xl"],
[data-component="ChatArea.EmptyState"] [class*="shadow-md"],
[data-component="ChatArea.EmptyState"] [class*="shadow-sm"],
[data-component="ChatArea.EmptyState"] [class*="shadow-2xl"],
[data-component="ChatArea.EmptyState"] [class*="shadow-["] {
  box-shadow: none !important;
}

/* FAQ category badges ("TOP ISSUE", "SETUP", "CORE", "AGENTS",
 * "CONNECTIONS", etc.). The engine's CATEGORY_STYLES map paints
 * them as `border-{rose,amber,cyan,emerald,violet,fuchsia,orange}-400
 * bg-{same}-500/12 text-{same}-200` Tailwind utilities — period
 * incorrect. Flatten all to mono Win95 chips: shadow-gray field,
 * white text, hard 1-px black border. */
[data-component="ChatArea.EmptyState"] [class*="bg-rose-500"],
[data-component="ChatArea.EmptyState"] [class*="bg-amber-500"],
[data-component="ChatArea.EmptyState"] [class*="bg-cyan-500"],
[data-component="ChatArea.EmptyState"] [class*="bg-emerald-500"],
[data-component="ChatArea.EmptyState"] [class*="bg-violet-500"],
[data-component="ChatArea.EmptyState"] [class*="bg-fuchsia-500"],
[data-component="ChatArea.EmptyState"] [class*="bg-orange-500"] {
  background: var(--win95-shadow) !important;
  background-image: none !important;
  color: var(--win95-hilite) !important;
  border-color: var(--win95-text) !important;
}

/* Marinara logo. Engine paints `<img src="/logo.png">` inside a
 * rounded shadowed container — the image itself is a smooth
 * peach/pink gradient illustration. CSS can't repaint a raster
 * image into a Win95 bitmap, but full grayscale + boosted contrast
 * + pixelated rendering brings it close to a 16-color desktop icon
 * read. The container's bevel is provided by the EmptyState
 * rounded/shadow kills above. */
[data-component="ChatArea.EmptyState"] [class*="rounded-2xl"] img,
[data-component="ChatArea.EmptyState"] [class*="rounded-["] img,
[data-component="ChatArea.EmptyState"] img[src*="logo"] {
  filter: grayscale(1) contrast(1.4) brightness(0.95) !important;
  image-rendering: pixelated !important;
}

/* Logo container — give it a proper Win95 sunken portrait well so
 * the desaturated logo sits in a frame instead of floating. */
[data-component="ChatArea.EmptyState"] [class*="rounded-2xl"][class*="shadow"] {
  border: 2px solid !important;
  border-top-color: var(--win95-shadow) !important;
  border-left-color: var(--win95-shadow) !important;
  border-right-color: var(--win95-hilite) !important;
  border-bottom-color: var(--win95-hilite) !important;
  box-shadow:
    inset 1px 1px 0 var(--win95-dark),
    inset -1px -1px 0 var(--win95-light) !important;
  background: var(--win95-face) !important;
}

/* Discord / Support footer buttons on the home page. Engine renders
 * these as `<a>` with `rounded-full` + Discord/heart glyphs. Pin
 * Win95 raised button bevel. */
[data-component="ChatArea.EmptyState"] a[href*="discord.com"],
[data-component="ChatArea.EmptyState"] a[href*="github.com"],
[data-component="ChatArea.EmptyState"] a[href*="ko-fi"] {
  background: var(--win95-face) !important;
  color: var(--win95-text) !important;
  border: 2px solid !important;
  border-top-color: var(--win95-light) !important;
  border-left-color: var(--win95-light) !important;
  border-right-color: var(--win95-dark) !important;
  border-bottom-color: var(--win95-dark) !important;
  box-shadow:
    inset 1px 1px 0 var(--win95-hilite),
    inset -1px -1px 0 var(--win95-shadow) !important;
  border-radius: 0 !important;
  padding: 3px 10px !important;
  text-decoration: none !important;
}

/* Marinara wordmark sparkles `✧ Marinara Engine ✧` + similar
 * decorative glyphs (✨, ⋆, ✦) anywhere they decorate Marinara
 * branding. The literal Unicode characters inside `.retro-glow-text`
 * are stripped by JS (sparkleStrip in win95-theme.js) on the 1Hz
 * reconcile tick. CSS just removes the modern glow effect. */
.retro-glow-text {
  text-shadow: none !important;
  background: none !important;
  background-image: none !important;
  -webkit-text-fill-color: var(--win95-text) !important;
  background-clip: border-box !important;
  -webkit-background-clip: border-box !important;
  color: var(--win95-text) !important;
  animation: none !important;
}

/* ── Chat input bar (structural target) ──────────────────────
 * Both `mari-chat-input-box` AND `mari-chat-input` /
 * `chat-input-container` source classes are stripped from the
 * rendered DOM (twMerge or build transform — confirmed via
 * DevTools `getComputedStyle` returning null on those selectors,
 * same gotcha as `mari-chat-send-btn` in v1). Target by
 * structure instead: the chat input pill is uniquely identified
 * as a div inside `.mari-chat-area` (or `.rpg-chat-area`) that
 * carries both Tailwind `rounded-2xl` AND `bg-black/X` classes.
 * No other element on the surface fits that signature. */
.mari-chat-area div[class*="rounded-2xl"][class*="bg-black"],
.rpg-chat-area div[class*="rounded-2xl"][class*="bg-black"],
[data-component^="ChatArea"] div[class*="rounded-2xl"][class*="bg-black"] {
  border-radius: 0 !important;
  background: var(--win95-face) !important;
  background-color: var(--win95-face) !important;
  background-image: none !important;
  border: 2px solid !important;
  border-top-color: var(--win95-light) !important;
  border-left-color: var(--win95-light) !important;
  border-right-color: var(--win95-dark) !important;
  border-bottom-color: var(--win95-dark) !important;
  box-shadow:
    inset 1px 1px 0 var(--win95-hilite),
    inset -1px -1px 0 var(--win95-shadow) !important;
}

/* ── Avatars (chunky-pixel, desaturated) ──────────────────────
 * Engine renders chat-list and message avatars as smooth-scaled
 * round photos with a green presence dot — pure 2024 messaging
 * convention. Win95 had 16-color bitmap icons with hard pixel
 * edges. We can't replace user-uploaded thumbnails, but we can
 * push them visually toward "looks chunky and 16-color" with:
 *   - `image-rendering: pixelated` so the browser nearest-
 *     neighbor scales instead of bilinear-smoothing
 *   - `border-radius: 0` so the frame is square (the engine
 *     uses `rounded-full`)
 *   - `filter: saturate(0.6) contrast(1.1)` to dial back the
 *     vivid HD photo look
 * Scoped to chat-list and message rows; uploaded images inside
 * message content stay user-styled.
 *
 * Selector hits the engine's `<img className="...rounded-full
 * object-cover">` avatar pattern — both single-character and
 * stacked group avatars. */
:where(
  [data-component="ChatSidebar"],
  [data-component^="ChatArea"]
) img[class*="rounded-full"]:not(.mari-message-content img),
:where(
  [data-component="ChatSidebar"],
  [data-component^="ChatArea"]
) img[class*="rounded-md"]:not(.mari-message-content img),
:where(
  [data-component="ChatSidebar"],
  [data-component^="ChatArea"]
) .mari-message-avatar img {
  image-rendering: pixelated;
  image-rendering: -moz-crisp-edges;
  border-radius: 0 !important;
  filter: saturate(0.6) contrast(1.1);
}

/* The avatar's parent container is also `rounded-full` (sets the
 * clip), so square the parent too. */
:where(
  [data-component="ChatSidebar"],
  [data-component^="ChatArea"]
) div[class*="rounded-full"]:not(.mari-message-content *):has(> img),
:where(
  [data-component="ChatSidebar"],
  [data-component^="ChatArea"]
) div[class*="rounded-full"]:not(.mari-message-content *):has(> div[class*="rounded-full"]) {
  border-radius: 0 !important;
}

/* ── Hyperlinks ───────────────────────────────────────────────
 * Win95 classic links — `#0000ee` solid blue with underline,
 * `#551a8b` purple after visit. Engine renders home-page links
 * (Marinara / LinkAPI / Huntercolliex etc.) with Tailwind
 * `text-primary` / `text-blue-X` and inconsistent underlining.
 * Force the canonical IE3-era treatment everywhere inside our
 * chrome surfaces and the home page. Skips anchors inside
 * message-content (chat body) so users can keep their content
 * styling intact. */
:where(
  [data-component="ChatSidebar"],
  [data-component="RightPanel"],
  [data-component^="ChatArea"],
  [data-component="TopBar"],
  .mari-modal-panel,
  .os-window
) a:not(.mari-message-content a):not(.win95-skip) {
  color: var(--win95-link) !important;
  text-decoration: underline !important;
  text-shadow: none !important;
  background: none !important;
  background-image: none !important;
  -webkit-text-fill-color: var(--win95-link) !important;
}

:where(
  [data-component="ChatSidebar"],
  [data-component="RightPanel"],
  [data-component^="ChatArea"],
  [data-component="TopBar"],
  .mari-modal-panel,
  .os-window
) a:not(.mari-message-content a):not(.win95-skip):visited {
  color: #551a8b !important;
  -webkit-text-fill-color: #551a8b !important;
}

/* ── Boot splash (Win95-style "Starting Marinara…" splash) ───────
 * Full-viewport black overlay shown once per browser session
 * (sessionStorage gated). Auto-dismisses after ~2.6 seconds or
 * on first click. JS in win95-theme.js builds the DOM; CSS owns
 * everything visual. The four-color flag is a 2×2 grid (red /
 * green / blue / yellow) — close-enough nod to the Win95 flag
 * without going through the perspective trapezoid contortions
 * the real boot screen used. */
.win95-boot-splash {
  position: fixed;
  inset: 0;
  z-index: 999999;
  background: #000;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  font-family: var(--font-y2k);
  color: var(--win95-hilite);
  /* Skip the chrome animation defeat — the splash needs its
   * progress-bar fill animation to actually run. */
  animation: win95-boot-fade-in 200ms ease-out;
}

@keyframes win95-boot-fade-in {
  from { opacity: 0; }
  to { opacity: 1; }
}

.win95-boot-content {
  text-align: center;
  max-width: 80vw;
  user-select: none;
}

.win95-boot-flag {
  display: grid;
  grid-template-columns: 1fr 1fr;
  grid-template-rows: 1fr 1fr;
  gap: 4px;
  width: 84px;
  height: 84px;
  margin: 0 auto 28px;
}
.win95-boot-flag > div {
  border: 1px solid rgba(0, 0, 0, 0.5);
}
.win95-boot-flag > div:nth-child(1) { background: #e23030; }
.win95-boot-flag > div:nth-child(2) { background: #2db835; }
.win95-boot-flag > div:nth-child(3) { background: #2858d0; }
.win95-boot-flag > div:nth-child(4) { background: #ecc828; }

.win95-boot-title {
  font-size: 36px;
  font-weight: bold;
  letter-spacing: 4px;
  margin-bottom: 6px;
  text-shadow: 2px 2px 0 rgba(0, 0, 0, 0.7);
  font-family: var(--font-y2k);
}

.win95-boot-tagline {
  font-size: 12px;
  letter-spacing: 2px;
  opacity: 0.65;
  margin-bottom: 24px;
  font-family: var(--font-y2k);
}

.win95-boot-status {
  font-size: 13px;
  margin: 22px 0 14px;
  letter-spacing: 1px;
}

/* Sunken progress trough + segmented blue fill. The
 * repeating-linear-gradient draws the 12-px navy slabs separated
 * by 2-px gaps — Win95 progress bars rendered as discrete
 * vertical blocks rather than a smooth fill. */
.win95-boot-bar {
  width: 280px;
  height: 18px;
  margin: 14px auto 26px;
  background: var(--win95-shadow);
  padding: 2px;
  border: 2px solid;
  border-top-color: var(--win95-dark);
  border-left-color: var(--win95-dark);
  border-right-color: var(--win95-light);
  border-bottom-color: var(--win95-light);
  box-sizing: border-box;
}

.win95-boot-bar-fill {
  height: 100%;
  width: 0;
  background-image: repeating-linear-gradient(
    to right,
    var(--win95-title-active-1) 0,
    var(--win95-title-active-1) 12px,
    transparent 12px,
    transparent 14px
  );
  animation: win95-boot-fill 2.4s linear forwards;
}

@keyframes win95-boot-fill {
  from { width: 0; }
  to { width: 100%; }
}

.win95-boot-hint {
  font-size: 11px;
  opacity: 0.55;
  margin-top: 22px;
  letter-spacing: 1px;
  font-family: var(--font-y2k);
}

/* ── Settings panel (own UI — Ctrl+Shift+9 / #win95) ─────────────── */
.win95-settings {
  position: fixed;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  z-index: 99999;
  width: 320px;
  max-width: calc(100vw - 32px);
  background: var(--win95-face);
  color: var(--win95-text);
  font-family: var(--font-y2k);
  font-size: 11px;
  border: 2px solid;
  border-top-color: var(--win95-light);
  border-left-color: var(--win95-light);
  border-right-color: var(--win95-dark);
  border-bottom-color: var(--win95-dark);
  box-shadow:
    inset 1px 1px 0 var(--win95-hilite),
    inset -1px -1px 0 var(--win95-shadow),
    2px 2px 0 var(--win95-dark);
  padding: 4px;
}

.win95-settings.is-hidden { display: none; }

.win95-settings-titlebar {
  display: flex;
  align-items: center;
  gap: 4px;
  height: 20px;
  padding: 2px 3px 2px 4px;
  background: linear-gradient(
    to right,
    var(--win95-title-active-1) 0%,
    var(--win95-title-active-2) 100%
  );
  color: var(--win95-hilite);
  font-weight: 700;
  user-select: none;
}

.win95-settings-titlebar-title { flex: 1; }

.win95-settings-body {
  padding: 12px 10px 10px;
}

.win95-settings-row {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-bottom: 10px;
}

.win95-settings-row label { cursor: default; }

.win95-settings-actions {
  display: flex;
  justify-content: flex-end;
  gap: 6px;
  margin-top: 14px;
}

.win95-settings-help {
  margin: 12px 0 0;
  padding: 6px 8px;
  font-size: 11px;
  line-height: 1.4;
  border: 2px solid;
  border-top-color: var(--win95-shadow);
  border-left-color: var(--win95-shadow);
  border-right-color: var(--win95-hilite);
  border-bottom-color: var(--win95-hilite);
  background: var(--win95-hilite);
  color: var(--win95-text);
}

